"use server";

import { db } from "@/lib/db";
import { aiInteractions } from "@/lib/db/schema";
import { validateSessionOwnership } from "@/lib/actions/validate-session-ownership";

interface LogAIInteractionData {
  sourceId?: string;
  documentId: string;
  sessionId?: string;
  mode: string;
  prompt: string;
  selectedText?: string;
  response: string;
  action: string;
  documentDiff?: unknown;
  charactersInserted?: number;
  provider: string;
  model: string;
}

export async function logAIInteraction(data: LogAIInteractionData) {
  await validateSessionOwnership({
    documentId: data.documentId,
    sourceId: data.sourceId,
    sessionId: data.sessionId,
  });

  const [interaction] = await db
    .insert(aiInteractions)
    .values({
      ...(data.sourceId ? { id: data.sourceId } : {}),
      documentId: data.documentId,
      sessionId: data.sessionId,
      mode: data.mode,
      prompt: data.prompt,
      selectedText: data.selectedText,
      response: data.response,
      action: data.action,
      documentDiff: data.documentDiff,
      charactersInserted: data.charactersInserted ?? 0,
      provider: data.provider,
      model: data.model,
    })
    .returning();

  return interaction;
}

"use server";

import { db } from "@/lib/db";
import {
  badges,
  aiInteractions,
  pasteEvents,
  writingSessions,
  revisions,
  chatThreads,
} from "@/lib/db/schema";
import { requireDocumentOwner } from "@/lib/auth/authorize";
import {
  calculateMetrics,
  estimateRetainedAiCharactersFromAcceptedResponses,
} from "@/lib/metrics";
import { extractPlainText } from "@/lib/tiptap-utils";
import { generateBadgeHtml, generateBadgeMarkdown } from "@/lib/badge-snippets";
import { nanoid } from "nanoid";
import { eq } from "drizzle-orm";
import { revalidatePath } from "next/cache";

export async function generateBadge(documentId: string) {
  const { document } = await requireDocumentOwner(documentId);

  // Fetch audit trail data
  const [interactions, pastes, sessions, documentRevisions, threads] = await Promise.all([
    db
      .select()
      .from(aiInteractions)
      .where(eq(aiInteractions.documentId, documentId)),
    db
      .select()
      .from(pasteEvents)
      .where(eq(pasteEvents.documentId, documentId)),
    db
      .select()
      .from(writingSessions)
      .where(eq(writingSessions.documentId, documentId)),
    db
      .select()
      .from(revisions)
      .where(eq(revisions.documentId, documentId)),
    db
      .select({
        mode: chatThreads.mode,
        summary: chatThreads.summary,
        messageCount: chatThreads.messageCount,
        createdAt: chatThreads.createdAt,
      })
      .from(chatThreads)
      .where(eq(chatThreads.documentId, documentId)),
  ]);

  // Extract plain text and calculate metrics
  const content = document.content as Parameters<typeof extractPlainText>[0];
  const documentText = extractPlainText(content);
  const metrics = calculateMetrics(content);
  const fallbackAiChars = estimateRetainedAiCharactersFromAcceptedResponses(
    documentText,
    interactions
  );
  const fallbackAiPct =
    metrics.total_characters > 0
      ? Math.floor(
          (Math.min(fallbackAiChars, metrics.total_characters) /
            metrics.total_characters) *
            100
        )
      : 0;
  const resolvedAiPercentage = Math.max(metrics.ai_percentage, fallbackAiPct);

  // Calculate stats
  const totalActiveSeconds = sessions.reduce(
    (sum, s) => sum + (s.activeSeconds ?? 0),
    0
  );

  const stats = {
    ai_percentage: resolvedAiPercentage,
    external_paste_percentage: metrics.external_paste_percentage,
    interaction_count: interactions.length,
    session_count: sessions.length,
    total_active_seconds: totalActiveSeconds,
    total_characters: metrics.total_characters,
    chat_thread_count: threads.length,
  };

  // Generate verification ID
  const verificationId = nanoid(21);

  // Freeze the audit trail
  const auditTrail = {
    ai_interactions: interactions.map((i) => ({
      sourceId: i.id,
      mode: i.mode,
      prompt: i.prompt,
      selectedText: i.selectedText,
      response: i.response,
      action: i.action,
      provider: i.provider,
      model: i.model,
      createdAt: i.createdAt,
    })),
    paste_events: pastes.map((p) => ({
      sourceId: p.id,
      sourceType: p.sourceType,
      characterCount: p.characterCount,
      createdAt: p.createdAt,
    })),
    writing_sessions: sessions.map((s) => ({
      startedAt: s.startedAt,
      endedAt: s.endedAt,
      activeSeconds: s.activeSeconds,
    })),
    revisions: documentRevisions.map((r) => ({
      trigger: r.trigger,
      createdAt: r.createdAt,
    })),
    chat_threads: threads.map((t) => ({
      mode: t.mode,
      summary: t.summary,
      messageCount: t.messageCount,
      createdAt: t.createdAt,
    })),
  };

  // Insert badge record (insert-only, no update or delete)
  const [badge] = await db
    .insert(badges)
    .values({
      documentId,
      verificationId,
      documentTitle: document.title,
      documentText,
      documentContent: document.content,
      auditTrail,
      stats,
    })
    .returning();

  // Generate embed snippets
  const badgeHtml = generateBadgeHtml(verificationId, resolvedAiPercentage);
  const badgeMarkdown = generateBadgeMarkdown(
    verificationId,
    resolvedAiPercentage
  );

  return {
    ...badge,
    badgeHtml,
    badgeMarkdown,
  };
}

export async function takedownBadge(badgeId: string, reason?: string) {
  const [badge] = await db
    .select()
    .from(badges)
    .where(eq(badges.id, badgeId));

  if (!badge) throw new Error("Badge not found");

  // Verify ownership through document
  await requireDocumentOwner(badge.documentId);

  await db
    .update(badges)
    .set({
      isTakenDown: true,
      takedownReason: reason ?? null,
    })
    .where(eq(badges.id, badgeId));

  // Trigger on-demand revalidation for the verification page and badge image
  revalidatePath(`/verify/${badge.verificationId}`);
  revalidatePath(`/api/badges/${badge.verificationId}/image`);
}

"use server";

import { db } from "@/lib/db";
import { chatThreads } from "@/lib/db/schema";
import { requireDocumentOwner } from "@/lib/auth/authorize";
import { eq, and, desc } from "drizzle-orm";

// Whitelist of allowed summary keys to prevent arbitrary client data
// from flowing into the public badge audit trail.
const ALLOWED_SUMMARY_KEYS = new Set([
  "messageCount",
  "durationMinutes",
  "category",
  "provider",
  "model",
  "tokenCount",
]);

function sanitizeSummary(
  raw: Record<string, unknown> | undefined
): Record<string, unknown> | undefined {
  if (!raw) return undefined;
  const clean: Record<string, unknown> = {};
  for (const key of Object.keys(raw)) {
    if (!ALLOWED_SUMMARY_KEYS.has(key)) continue;
    const val = raw[key];
    if (typeof val === "string" || typeof val === "number") {
      clean[key] = val;
    }
  }
  return clean;
}

export async function getChatThreads(documentId: string) {
  await requireDocumentOwner(documentId);

  return db
    .select({
      id: chatThreads.id,
      title: chatThreads.title,
      messageCount: chatThreads.messageCount,
      updatedAt: chatThreads.updatedAt,
    })
    .from(chatThreads)
    .where(eq(chatThreads.documentId, documentId))
    .orderBy(desc(chatThreads.updatedAt));
}

export async function getChatThread(threadId: string) {
  const [thread] = await db
    .select()
    .from(chatThreads)
    .where(eq(chatThreads.id, threadId));

  if (!thread) throw new Error("Not found");

  await requireDocumentOwner(thread.documentId);

  return thread;
}

export async function saveChatThread(data: {
  documentId: string;
  threadId?: string;
  title?: string;
  messages: unknown[];
  messageCount: number;
  summary?: Record<string, unknown>;
}) {
  const { user } = await requireDocumentOwner(data.documentId);
  const safeSummary = sanitizeSummary(data.summary);

  if (data.threadId) {
    // Update existing thread — scope to documentId + userId to prevent
    // cross-user updates if someone guesses a thread ID.
    const [updated] = await db
      .update(chatThreads)
      .set({
        title: data.title,
        messages: data.messages,
        messageCount: data.messageCount,
        summary: safeSummary,
        updatedAt: new Date(),
      })
      .where(
        and(
          eq(chatThreads.id, data.threadId),
          eq(chatThreads.documentId, data.documentId),
          eq(chatThreads.userId, user.id!)
        )
      )
      .returning();

    if (!updated) throw new Error("Not found");

    return updated;
  }

  // Create new thread
  const [created] = await db
    .insert(chatThreads)
    .values({
      documentId: data.documentId,
      userId: user.id!,
      title: data.title ?? "New conversation",
      messages: data.messages,
      messageCount: data.messageCount,
      summary: safeSummary,
    })
    .returning();

  return created;
}

export async function deleteChatThread(threadId: string) {
  const [thread] = await db
    .select()
    .from(chatThreads)
    .where(eq(chatThreads.id, threadId));

  if (!thread) throw new Error("Not found");

  await requireDocumentOwner(thread.documentId);

  await db.delete(chatThreads).where(eq(chatThreads.id, threadId));
}

"use server";

import { db } from "@/lib/db";
import { documents } from "@/lib/db/schema";
import { requireAuth, requireDocumentOwner } from "@/lib/auth/authorize";
import { eq } from "drizzle-orm";
import { revalidatePath } from "next/cache";

export async function createDocument() {
  const user = await requireAuth();

  const [document] = await db
    .insert(documents)
    .values({ userId: user.id! })
    .returning();

  return document;
}

export async function updateDocument(
  documentId: string,
  data: { title?: string; content?: unknown; wordCount?: number }
) {
  await requireDocumentOwner(documentId);

  const [updated] = await db
    .update(documents)
    .set({
      ...data,
      content: data.content !== undefined ? data.content : undefined,
      updatedAt: new Date(),
    })
    .where(eq(documents.id, documentId))
    .returning();

  return updated;
}

export async function deleteDocument(documentId: string) {
  await requireDocumentOwner(documentId);

  await db
    .update(documents)
    .set({ deletedAt: new Date() })
    .where(eq(documents.id, documentId));

  revalidatePath("/dashboard");
}

"use server";

import { db } from "@/lib/db";
import { pasteEvents } from "@/lib/db/schema";
import { validateSessionOwnership } from "@/lib/actions/validate-session-ownership";

interface LogPasteEventData {
  sourceId?: string;
  documentId: string;
  sessionId?: string;
  content: string;
  sourceType: string;
  characterCount: number;
}

export async function logPasteEvent(data: LogPasteEventData) {
  await validateSessionOwnership({
    documentId: data.documentId,
    sourceId: data.sourceId,
    sessionId: data.sessionId,
  });

  const [event] = await db
    .insert(pasteEvents)
    .values({
      ...(data.sourceId ? { id: data.sourceId } : {}),
      documentId: data.documentId,
      sessionId: data.sessionId,
      content: data.content,
      sourceType: data.sourceType,
      characterCount: data.characterCount,
    })
    .returning();

  return event;
}

"use server";

import { db } from "@/lib/db";
import { revisions } from "@/lib/db/schema";
import { requireDocumentOwner } from "@/lib/auth/authorize";
import { extractPlainText } from "@/lib/tiptap-utils";

interface CreateRevisionData {
  documentId: string;
  content: Record<string, unknown>;
  trigger: string;
}

export async function createRevision(data: CreateRevisionData) {
  await requireDocumentOwner(data.documentId);

  const plainText = extractPlainText(
    data.content as Parameters<typeof extractPlainText>[0]
  );

  const [revision] = await db
    .insert(revisions)
    .values({
      documentId: data.documentId,
      content: data.content,
      plainText,
      trigger: data.trigger,
    })
    .returning();

  return revision;
}

"use server";

import { db } from "@/lib/db";
import { writingSessions } from "@/lib/db/schema";
import { requireAuth, requireDocumentOwner } from "@/lib/auth/authorize";
import { and, eq, sql } from "drizzle-orm";

export async function startSession(documentId: string) {
  const { user } = await requireDocumentOwner(documentId);
  const now = new Date();

  const [session] = await db
    .insert(writingSessions)
    .values({
      documentId,
      userId: user.id,
      startedAt: now,
      lastHeartbeat: now,
      activeSeconds: 0,
    })
    .returning();

  return session;
}

export async function heartbeat(sessionId: string) {
  const user = await requireAuth();
  const now = new Date();

  // Compute elapsed seconds from lastHeartbeat, clamped to [0, 60]
  const [session] = await db
    .update(writingSessions)
    .set({
      lastHeartbeat: now,
      activeSeconds: sql`${writingSessions.activeSeconds} + LEAST(GREATEST(EXTRACT(EPOCH FROM ${now}::timestamp - ${writingSessions.lastHeartbeat})::int, 0), 60)`,
    })
    .where(
      and(
        eq(writingSessions.id, sessionId),
        eq(writingSessions.userId, user.id)
      )
    )
    .returning();

  if (!session) {
    throw new Error("Not found");
  }

  return session;
}

export async function endSession(sessionId: string) {
  const user = await requireAuth();

  const [session] = await db
    .update(writingSessions)
    .set({
      endedAt: new Date(),
    })
    .where(
      and(
        eq(writingSessions.id, sessionId),
        eq(writingSessions.userId, user.id)
      )
    )
    .returning();

  if (!session) {
    throw new Error("Not found");
  }
}

"use server";

import { db } from "@/lib/db";
import { users } from "@/lib/db/schema";
import { requireAuth } from "@/lib/auth/authorize";
import { eq } from "drizzle-orm";
import { providers } from "@/lib/ai/providers";

function validateProviderModel(providerId: string, modelId: string): boolean {
  const provider = providers[providerId];
  if (!provider) return false;
  return provider.models.some((m) => m.id === modelId);
}

export async function updateUserPreferences(data: {
  aiProvider: string;
  aiModel: string;
}) {
  const user = await requireAuth();

  if (!validateProviderModel(data.aiProvider, data.aiModel)) {
    throw new Error("Invalid provider/model combination");
  }

  const [updated] = await db
    .update(users)
    .set({
      aiProvider: data.aiProvider,
      aiModel: data.aiModel,
    })
    .where(eq(users.id, user.id!))
    .returning();

  return updated;
}

export async function getUserPreferences() {
  const user = await requireAuth();

  const [result] = await db
    .select({
      aiProvider: users.aiProvider,
      aiModel: users.aiModel,
    })
    .from(users)
    .where(eq(users.id, user.id!));

  return result ?? { aiProvider: "anthropic", aiModel: null };
}

import { streamText, convertToModelMessages } from "ai";
import { getModel } from "@/lib/ai/providers";
import { getSystemPrompt } from "@/lib/ai/system-prompts";
import { checkRateLimit } from "@/lib/ai/rate-limit";
import { aiCompletionSchema } from "@/lib/ai/schemas";
import {
  contentFilterMetadata,
  parseAiRequestBody,
  requireSessionUserId,
  resolveProviderModelForUser,
} from "@/lib/ai/route-utils";

export const maxDuration = 30;
const MAX_COMPLETE_BODY_BYTES = 300_000;

function buildMessageSystemPrompt(basePrompt: string, context?: string) {
  return context ? `${basePrompt}\n\nDocument context:\n${context}` : basePrompt;
}

function buildSinglePrompt(
  prompt: string,
  selectedText?: string,
  context?: string
) {
  const selectedInstruction = selectedText
    ? `Selected text: "${selectedText}"\n\nInstruction: ${prompt}`
    : prompt;
  return context
    ? `Document context:\n${context}\n\n${selectedInstruction}`
    : selectedInstruction;
}

function toUiStreamResponse(result: Awaited<ReturnType<typeof streamText>>) {
  return result.toUIMessageStreamResponse({
    messageMetadata: ({
      part,
    }: {
      part: { type: string; finishReason?: string };
    }) => contentFilterMetadata(part),
  });
}

async function streamConversationCompletion(params: {
  aiModel: ReturnType<typeof getModel>;
  systemPrompt: string;
  context?: string;
  messages: Parameters<typeof convertToModelMessages>[0];
}) {
  const result = streamText({
    model: params.aiModel,
    system: buildMessageSystemPrompt(params.systemPrompt, params.context),
    messages: await convertToModelMessages(params.messages),
  });

  return toUiStreamResponse(result);
}

async function streamSinglePromptCompletion(params: {
  aiModel: ReturnType<typeof getModel>;
  systemPrompt: string;
  prompt: string;
  selectedText?: string;
  context?: string;
}) {
  const result = streamText({
    model: params.aiModel,
    system: params.systemPrompt,
    prompt: buildSinglePrompt(params.prompt, params.selectedText, params.context),
  });

  return toUiStreamResponse(result);
}

export async function POST(req: Request) {
  const userId = await requireSessionUserId();
  if (userId instanceof Response) {
    return userId;
  }

  const parsed = await parseAiRequestBody(
    req,
    MAX_COMPLETE_BODY_BYTES,
    aiCompletionSchema
  );
  if ("response" in parsed) {
    return parsed.response;
  }

  const { messages, prompt, context, selectedText, mode, provider, model } =
    parsed.data;

  const providerModel = await resolveProviderModelForUser(userId, {
    provider,
    model,
  });
  if ("response" in providerModel) {
    return providerModel.response;
  }
  const resolvedProvider = providerModel.provider;
  const resolvedModel = providerModel.model;

  // Rate limit check (database-backed, serverless-safe)
  const { allowed } = await checkRateLimit(userId);
  if (!allowed) {
    return Response.json(
      { error: "Rate limit exceeded. Max 20 requests per minute." },
      { status: 429 }
    );
  }

  const systemPrompt = getSystemPrompt(mode);
  const aiModel = getModel(resolvedProvider, resolvedModel);

  try {
    if (messages) {
      return streamConversationCompletion({
        aiModel,
        systemPrompt,
        context,
        messages: messages as Parameters<typeof convertToModelMessages>[0],
      });
    }

    if (!prompt) {
      return Response.json({ error: "Prompt is required" }, { status: 400 });
    }

    return streamSinglePromptCompletion({
      aiModel,
      systemPrompt,
      prompt,
      selectedText,
      context,
    });
  } catch (error) {
    console.error("[AI Complete] Error:", error);
    return Response.json(
      { error: error instanceof Error ? error.message : "Internal server error" },
      { status: 500 }
    );
  }
}

import { db } from "@/lib/db";
import { badges } from "@/lib/db/schema";
import { eq } from "drizzle-orm";
import { generateBadgeImage } from "@/lib/badge-image";
import { NextResponse } from "next/server";

export async function GET(
  _request: Request,
  { params }: { params: Promise<{ verificationId: string }> }
) {
  const { verificationId } = await params;

  const [badge] = await db
    .select()
    .from(badges)
    .where(eq(badges.verificationId, verificationId));

  if (!badge) {
    return new NextResponse("Not Found", { status: 404 });
  }

  if (badge.isTakenDown) {
    return new NextResponse("Gone", {
      status: 410,
      headers: { "Cache-Control": "no-store" },
    });
  }

  const stats = badge.stats as { ai_percentage: number };
  const imageResponse = generateBadgeImage(stats.ai_percentage);

  // Clone the response to add cache headers
  const response = new NextResponse(imageResponse.body, {
    headers: {
      "Content-Type": "image/png",
      "Cache-Control":
        "public, s-maxage=86400, stale-while-revalidate=86400",
    },
  });

  return response;
}

import { auth } from "@/auth";
import { db } from "@/lib/db";
import { badges, documents } from "@/lib/db/schema";
import { eq, and, isNull, desc } from "drizzle-orm";
import { NextRequest, NextResponse } from "next/server";

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

export async function GET(request: NextRequest) {
  const session = await auth();

  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const documentId = request.nextUrl.searchParams.get("documentId");

  if (!documentId || !UUID_RE.test(documentId)) {
    return NextResponse.json(
      { error: "documentId required" },
      { status: 400 }
    );
  }

  // Verify document ownership
  const [document] = await db
    .select()
    .from(documents)
    .where(
      and(eq(documents.id, documentId), isNull(documents.deletedAt))
    );

  if (!document || document.userId !== session.user.id) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  const documentBadges = await db
    .select({
      id: badges.id,
      verificationId: badges.verificationId,
      stats: badges.stats,
      createdAt: badges.createdAt,
    })
    .from(badges)
    .where(eq(badges.documentId, documentId))
    .orderBy(desc(badges.createdAt));

  return NextResponse.json(documentBadges);
}

import { streamText, smoothStream, convertToModelMessages } from "ai";
import { getModel } from "@/lib/ai/providers";
import { getSystemPrompt } from "@/lib/ai/system-prompts";
import { checkRateLimit } from "@/lib/ai/rate-limit";
import { chatRequestSchema } from "@/lib/ai/schemas";
import {
  parseAiRequestBody,
  requireSessionUserId,
  resolveProviderModelForUser,
} from "@/lib/ai/route-utils";

export const maxDuration = 60;
const MAX_CHAT_BODY_BYTES = 400_000;

function buildChatSystemPrompt(documentContext?: string) {
  const systemPrompt = getSystemPrompt("chat");
  if (!documentContext) {
    return systemPrompt;
  }
  return `${systemPrompt}\n\n---\nWriter's document:\n${documentContext}\n---`;
}

function buildChatMetadata(
  part: { type: string; finishReason?: string; usage?: { totalTokens?: number } },
  provider: string,
  model: string
) {
  if (part.type !== "finish") {
    return undefined;
  }

  return {
    provider,
    model,
    blocked: part.finishReason === "content-filter",
    ...(part.usage ? { tokenCount: part.usage.totalTokens } : {}),
  };
}

export async function POST(req: Request) {
  const userId = await requireSessionUserId();
  if (userId instanceof Response) {
    return userId;
  }

  const parsed = await parseAiRequestBody(req, MAX_CHAT_BODY_BYTES, chatRequestSchema);
  if ("response" in parsed) {
    return parsed.response;
  }

  const { messages, documentContext } = parsed.data;
  const providerModel = await resolveProviderModelForUser(userId, {
    provider: parsed.data.provider,
    model: parsed.data.model,
  });
  if ("response" in providerModel) {
    return providerModel.response;
  }
  const { provider, model } = providerModel;

  const { allowed } = await checkRateLimit(userId);
  if (!allowed) {
    return Response.json(
      { error: "Rate limit exceeded. Max 20 requests per minute." },
      { status: 429 }
    );
  }

  const system = buildChatSystemPrompt(documentContext);
  const aiModel = getModel(provider, model);

  try {
    const result = streamText({
      model: aiModel,
      system,
      messages: await convertToModelMessages(
        messages as Parameters<typeof convertToModelMessages>[0]
      ),
      experimental_transform: smoothStream({ chunking: "word" }),
    });

    return result.toUIMessageStreamResponse({
      sendReasoning: false,
      messageMetadata: ({
        part,
      }: {
        part: { type: string; finishReason?: string; usage?: { totalTokens?: number } };
      }) => buildChatMetadata(part, provider, model),
    });
  } catch (error) {
    console.error("[Chat] Error:", error);
    return Response.json(
      {
        error:
          error instanceof Error ? error.message : "Internal server error",
      },
      { status: 500 }
    );
  }
}

import { db } from "@/lib/db";
import {
  aiInteractions,
  pasteEvents,
  writingSessions,
  revisions,
