"use client";

import { useState, useCallback, useEffect, useRef } from "react";
import { Editor } from "@/components/editor/Editor";
import { useAutoSave } from "@/hooks/useAutoSave";
import { useSession } from "@/hooks/useSession";
import { SaveIndicator } from "@/components/editor/SaveIndicator";
import { BackLink } from "@/components/ui/BackLink";
import { Button } from "@/components/ui/button";
import Link from "next/link";

const PANEL_STATE_VERSION = 1;

interface StoredPanelState {
  version: number;
  chatOpen: boolean;
  editorOpen: boolean;
}

function panelStateKey(documentId: string): string {
  return `provenance:editor:${documentId}:panels`;
}

function readPanelState(documentId: string): Pick<StoredPanelState, "chatOpen" | "editorOpen"> {
  if (typeof window === "undefined") {
    return { chatOpen: true, editorOpen: true };
  }

  try {
    const raw = window.localStorage.getItem(panelStateKey(documentId));
    if (!raw) return { chatOpen: true, editorOpen: true };
    const parsed = JSON.parse(raw) as Partial<StoredPanelState>;
    if (parsed.version !== PANEL_STATE_VERSION) {
      return { chatOpen: true, editorOpen: true };
    }
    const chatOpen = parsed.chatOpen !== false;
    const editorOpen = parsed.editorOpen !== false;
    if (!chatOpen && !editorOpen) {
      return { chatOpen: true, editorOpen: true };
    }
    return { chatOpen, editorOpen };
  } catch {
    return { chatOpen: true, editorOpen: true };
  }
}

interface ThreadSummary {
  id: string;
  title: string;
  messageCount: number | null;
  updatedAt: Date | null;
}

interface EditorShellProps {
  documentId: string;
  initialTitle: string;
  initialContent: Record<string, unknown>;
  aiProvider: string;
  aiModel: string | null;
  latestBadgeVerificationId?: string | null;
  initialChatThreads?: ThreadSummary[];
}

export function EditorShell({
  documentId,
  initialTitle,
  initialContent,
  aiProvider,
  aiModel,
  latestBadgeVerificationId,
  initialChatThreads = [],
}: EditorShellProps) {
  const [title, setTitle] = useState(initialTitle);
  const [chatOpen, setChatOpen] = useState(
    () => readPanelState(documentId).chatOpen
  );
  const [editorOpen, setEditorOpen] = useState(
    () => readPanelState(documentId).editorOpen
  );
  const { save, status, retry, isDirty } = useAutoSave({ documentId, title });
  const { markActive } = useSession({ documentId });
  const isDirtyRef = useRef(isDirty);

  isDirtyRef.current = isDirty;

  const handleUpdate = useCallback(
    (json: Record<string, unknown>) => {
      markActive();
      save(json);
    },
    [save, markActive]
  );

  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      if (!isDirtyRef.current) return;

      const anchor = (e.target as HTMLElement).closest("a");
      if (!anchor) return;

      const href = anchor.getAttribute("href");
      if (!href || href.startsWith("http") || href.startsWith("#")) return;

      const confirmed = window.confirm(
        "You have unsaved changes. Are you sure you want to leave?"
      );

      if (!confirmed) {
        e.preventDefault();
        e.stopPropagation();
      }
    };

    document.addEventListener("click", handleClick, true);
    return () => document.removeEventListener("click", handleClick, true);
  }, []);

  useEffect(() => {
    if (typeof window === "undefined") return;
    window.localStorage.setItem(
      panelStateKey(documentId),
      JSON.stringify({
        version: PANEL_STATE_VERSION,
        chatOpen,
        editorOpen,
      } satisfies StoredPanelState)
    );
  }, [documentId, chatOpen, editorOpen]);

  return (
    <div className="flex min-h-0 flex-1 flex-col">
      <a href="#editor-content" className="sr-only focus:not-sr-only focus:absolute focus:z-50 focus:rounded-md focus:bg-background focus:px-3 focus:py-2 focus:text-sm focus:shadow-md">
        Skip to editor
      </a>
      <nav className="flex shrink-0 items-center gap-3 border-b border-border px-2 py-1.5" aria-label="Editor navigation">
        <BackLink href="/dashboard" />
        <input
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          aria-label="Document title"
          data-testid="document-title"
          className="flex-1 rounded-md bg-transparent px-1 text-lg font-semibold outline-none placeholder:text-muted-foreground focus-visible:ring-2 focus-visible:ring-ring/50"
          placeholder="Untitled"
        />
        <SaveIndicator status={status} onRetry={retry} />
        {latestBadgeVerificationId && (
          <Button variant="outline" size="sm" asChild>
            <Link href={`/verify/${latestBadgeVerificationId}`}>
              View Badge
            </Link>
          </Button>
        )}
        <Button variant="outline" size="sm" asChild>
          <Link href={`/editor/${documentId}/preview`} data-testid="generate-badge">
            Generate Badge
          </Link>
        </Button>
      </nav>
      <Editor
        content={initialContent}
        documentId={documentId}
        provider={aiProvider}
        model={aiModel ?? undefined}
        onUpdate={handleUpdate}
        chatOpen={chatOpen}
        onChatToggle={() => {
          if (!chatOpen || editorOpen) setChatOpen((v) => !v);
        }}
        editorOpen={editorOpen}
        onEditorToggle={() => {
          if (!editorOpen || chatOpen) setEditorOpen((v) => !v);
        }}
        initialChatThreads={initialChatThreads}
      />
    </div>
  );
}

export default function EditorLoading() {
  return (
    <div className="mx-auto max-w-4xl px-4 py-8">
      <div className="mb-6">
        <div className="h-8 w-24 animate-pulse rounded bg-muted" />
      </div>
      <div className="h-10 w-3/4 animate-pulse rounded bg-muted mb-4" />
      <div className="h-[60vh] w-full animate-pulse rounded bg-muted" />
    </div>
  );
}

import { auth } from "@/auth";
import { db } from "@/lib/db";
import { documents, users, chatThreads, badges } from "@/lib/db/schema";
import { eq, and, isNull, desc } from "drizzle-orm";
import { redirect, notFound } from "next/navigation";
import { EditorShell } from "./editor-shell";

async function requireSessionUserId() {
  const session = await auth();
  const userId = session?.user?.id;
  if (!userId) {
    redirect("/login");
  }
  return userId;
}

async function getOwnedDocument(documentId: string, userId: string) {
  const [document] = await db
    .select()
    .from(documents)
    .where(and(eq(documents.id, documentId), isNull(documents.deletedAt)));

  if (!document) {
    notFound();
  }

  if (document.userId !== userId) {
    redirect("/dashboard");
  }

  return document;
}

async function loadEditorMetadata(userId: string, documentId: string) {
  return Promise.all([
    db
      .select({ aiProvider: users.aiProvider, aiModel: users.aiModel })
      .from(users)
      .where(eq(users.id, userId))
      .then((rows) => rows[0]),
    db
      .select({
        id: chatThreads.id,
        title: chatThreads.title,
        messageCount: chatThreads.messageCount,
        updatedAt: chatThreads.updatedAt,
      })
      .from(chatThreads)
      .where(eq(chatThreads.documentId, documentId))
      .orderBy(desc(chatThreads.updatedAt)),
    db
      .select({ verificationId: badges.verificationId })
      .from(badges)
      .where(eq(badges.documentId, documentId))
      .orderBy(desc(badges.createdAt))
      .then((rows) => rows[0]),
  ]);
}

export default async function EditorPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const userId = await requireSessionUserId();
  const document = await getOwnedDocument(id, userId);
  const [prefs, threads, latestBadge] = await loadEditorMetadata(userId, id);

  return (
    <div className="flex h-screen flex-col px-2 py-1">
      <EditorShell
        documentId={document.id}
        initialTitle={document.title}
        initialContent={document.content as Record<string, unknown>}
        aiProvider={prefs?.aiProvider ?? "anthropic"}
        aiModel={prefs?.aiModel ?? null}
        latestBadgeVerificationId={latestBadge?.verificationId ?? null}
        initialChatThreads={threads}
      />
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { generateBadge } from "@/app/actions/badges";
import Link from "next/link";
import { AlertTriangle } from "lucide-react";
import { Button } from "@/components/ui/button";

interface PreviewPageProps {
  params: Promise<{ id: string }>;
}

export default function PreviewPage({ params }: PreviewPageProps) {
  return <PreviewContent params={params} />;
}

function PreviewContent({ params }: PreviewPageProps) {
  const [documentId, setDocumentId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [generating, setGenerating] = useState(false);
  const [badgeResult, setBadgeResult] = useState<{
    verificationId: string;
    badgeHtml: string;
    badgeMarkdown: string;
  } | null>(null);
  const [previewData, setPreviewData] = useState<{
    title: string;
    content: string;
    interactions: Array<{
      mode: string;
      prompt: string;
      response: string;
      action: string;
      createdAt: string | Date | null;
    }>;
    pasteEvents: Array<{
      sourceType: string;
      characterCount: number;
      createdAt: string | Date | null;
    }>;
  } | null>(null);
  const router = useRouter();

  useEffect(() => {
    let cancelled = false;
    (async () => {
      const { id } = await params;
      if (cancelled) return;
      setDocumentId(id);

      try {
        const res = await fetch(`/api/preview/${id}`);
        if (cancelled) return;
        if (res.status === 401 || res.status === 404) {
          router.push("/dashboard");
          return;
        }
        if (!res.ok) {
          router.push("/dashboard");
          return;
        }
        const data = await res.json();
        if (cancelled) return;
        setPreviewData(data);
      } catch {
        if (!cancelled) router.push("/dashboard");
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => { cancelled = true; };
  }, [params, router]);

  const handleConfirm = async () => {
    if (!documentId) return;
    setGenerating(true);
    try {
      const result = await generateBadge(documentId);
      setBadgeResult({
        verificationId: result.verificationId,
        badgeHtml: result.badgeHtml,
        badgeMarkdown: result.badgeMarkdown,
      });
    } catch (error) {
      console.error("Failed to generate badge:", error);
    } finally {
      setGenerating(false);
    }
  };

  if (loading) {
    return (
      <div className="mx-auto max-w-3xl px-4 py-8">
        <p className="text-muted-foreground">Loading preview...</p>
      </div>
    );
  }

  if (!previewData) {
    return (
      <div className="mx-auto max-w-3xl px-4 py-8">
        <p className="text-muted-foreground">Document not found.</p>
      </div>
    );
  }

  return (
    <div className="mx-auto max-w-3xl px-4 py-8">
      <div className="mb-6 flex items-center gap-4">
        <Link
          href={documentId ? `/editor/${documentId}` : "/dashboard"}
          className="text-sm text-muted-foreground hover:text-foreground"
        >
          &larr; Back to Editor
        </Link>
        <h1 className="text-xl font-semibold">Pre-Publish Preview</h1>
      </div>

      {/* Amber warning banner */}
      <div className="mb-6 flex items-start gap-3 rounded-lg border-b border-amber-200 bg-amber-50 px-4 py-3">
        <AlertTriangle className="mt-0.5 h-5 w-5 shrink-0 text-amber-600" />
        <p className="text-sm font-medium text-amber-800">
          Everything shown below will be publicly visible to anyone with the badge link.
        </p>
      </div>

      {/* Stat summary (3-col) */}
      <div className="mb-6 grid grid-cols-3 gap-3">
        <div className="rounded-lg border p-3 text-center">
          <div className="text-lg font-semibold">{previewData.interactions.length}</div>
          <div className="text-xs text-muted-foreground">AI Interactions</div>
        </div>
        <div className="rounded-lg border p-3 text-center">
          <div className="text-lg font-semibold">{previewData.pasteEvents.length}</div>
          <div className="text-xs text-muted-foreground">Paste Events</div>
        </div>
        <div className="rounded-lg border p-3 text-center">
          <div className="text-lg font-semibold">{previewData.content.split(/\s+/).filter(Boolean).length}</div>
          <div className="text-xs text-muted-foreground">Words</div>
        </div>
      </div>

      {/* Expandable sections */}
      {previewData.interactions.length > 0 && (
        <details className="mb-4 rounded-lg border border-violet-200 bg-violet-50/30">
          <summary className="cursor-pointer px-4 py-3 text-sm font-semibold">
            AI Interactions ({previewData.interactions.length})
          </summary>
          <div className="space-y-3 border-t px-4 py-3">
            {previewData.interactions.map((interaction, i) => (
              <div key={i} className="rounded-lg border bg-background p-3">
                <div className="mb-1 flex items-center gap-2 text-xs text-muted-foreground">
                  <span className="rounded bg-violet-100 px-2 py-0.5 font-medium text-violet-700">
                    {interaction.mode}
                  </span>
                  <span>{interaction.action}</span>
                </div>
                <p className="mb-1 text-sm">
                  <span className="font-medium">Prompt:</span> {interaction.prompt}
                </p>
                <p className="text-sm text-muted-foreground">
                  <span className="font-medium">Response:</span> {interaction.response}
                </p>
              </div>
            ))}
          </div>
        </details>
      )}

      {previewData.pasteEvents.length > 0 && (
        <details className="mb-4 rounded-lg border border-orange-200 bg-orange-50/30">
          <summary className="cursor-pointer px-4 py-3 text-sm font-semibold">
            Paste Events ({previewData.pasteEvents.length})
          </summary>
          <div className="space-y-2 border-t px-4 py-3">
            {previewData.pasteEvents.map((event, i) => (
              <div
                key={i}
                className="flex items-center justify-between rounded-lg border bg-background p-3 text-sm"
              >
                <span>{event.sourceType}</span>
                <span className="text-muted-foreground">{event.characterCount} characters</span>
              </div>
            ))}
          </div>
        </details>
      )}

      <details className="mb-6 rounded-lg border border-border">
        <summary className="cursor-pointer px-4 py-3 text-sm font-semibold">
          Document Text
        </summary>
        <div className="border-t px-4 py-3">
          <h3 className="mb-2 font-medium">{previewData.title}</h3>
          <div className="max-h-60 overflow-y-auto whitespace-pre-wrap text-sm text-muted-foreground">
            {previewData.content}
          </div>
        </div>
      </details>

      {/* Permanence note */}
      <div className="mb-6 rounded-lg bg-muted p-3 text-xs text-muted-foreground">
        Once generated, this badge and its audit trail are permanent and cannot be modified or deleted.
        The verification page will be publicly accessible via a unique URL.
      </div>

      {badgeResult ? (
        <section
          className="rounded-lg border border-green-500 bg-green-50 p-4 dark:bg-green-950"
          data-testid="badge-result"
        >
          <h2 className="mb-3 text-lg font-semibold text-green-800 dark:text-green-200">
            Badge Generated!
          </h2>
          <p className="mb-3 text-sm text-green-700 dark:text-green-300">
            Verification URL:{" "}
            <a
              href={`/verify/${badgeResult.verificationId}`}
              className="underline"
              data-testid="verification-url"
            >
              /verify/{badgeResult.verificationId}
            </a>
          </p>
          <div className="space-y-3">
            <div data-testid="badge-html-snippet">
              <label className="mb-1 block text-xs font-medium text-green-800 dark:text-green-200">
                HTML Embed
              </label>
              <pre className="overflow-x-auto rounded bg-white p-2 text-xs dark:bg-secondary">
                {badgeResult.badgeHtml}
