interface BadgeStats {
  ai_percentage: number;
  aiPercentage?: number;
  external_paste_percentage: number;
  interaction_count: number;
  session_count: number;
  total_active_seconds: number;
  total_characters: number;
}

interface AuditTrail {
  ai_interactions: Array<{
    mode: string;
    prompt: string;
    response: string;
    action: string;
    createdAt: string | Date | null;
  }>;
  paste_events: Array<{
    sourceType: string;
    characterCount: number;
    createdAt: string | Date | null;
  }>;
  writing_sessions: Array<{
    startedAt: string | Date | null;
    endedAt: string | Date | null;
    activeSeconds: number | null;
  }>;
  revisions: Array<{
    trigger: string;
    createdAt: string | Date | null;
  }>;
}

interface ViewAuditTrail {
  interactions: AuditTrail["ai_interactions"];
  pasteEvents: AuditTrail["paste_events"];
  sessions: AuditTrail["writing_sessions"];
  revisions: AuditTrail["revisions"];
}

interface ViewStats {
  ai_percentage: number;
  external_paste_percentage: number;
  interaction_count: number;
  session_count: number;
  total_active_seconds: number;
  total_characters: number;
}

function getAuditTrail(rawAuditTrail: unknown): AuditTrail {
  return (rawAuditTrail as AuditTrail) ?? {
    ai_interactions: [],
    paste_events: [],
    writing_sessions: [],
    revisions: [],
  };
}

function resolveDisplayMetrics(params: {
  stats: BadgeStats;
  documentContent: Parameters<typeof calculateMetrics>[0];
  finalTextSnapshot: string;
  interactions: AuditTrail["ai_interactions"];
}) {
  const { stats, documentContent, finalTextSnapshot, interactions } = params;
  const calculatedMetrics = calculateMetrics(documentContent);
  const fallbackAiChars = estimateRetainedAiCharactersFromAcceptedResponses(
    finalTextSnapshot,
    interactions
  );
  const fallbackAiPercentage =
    calculatedMetrics.total_characters > 0
      ? Math.floor(
          (Math.min(fallbackAiChars, calculatedMetrics.total_characters) /
            calculatedMetrics.total_characters) *
            100
        )
      : 0;

  return {
    aiPercentage: Math.max(
      stats.ai_percentage ?? stats.aiPercentage ?? 0,
      calculatedMetrics.ai_percentage,
      fallbackAiPercentage
    ),
    externalPastePercentage: Math.max(
      stats.external_paste_percentage ?? 0,
      calculatedMetrics.external_paste_percentage
    ),
    totalCharacters: Math.max(
      stats.total_characters ?? 0,
      calculatedMetrics.total_characters
    ),
  };
}

function TakedownNotice({ reason }: { reason: string | null }) {
  return (
    <div className="mx-auto max-w-2xl px-4 py-16 text-center">
      <h1 className="mb-4 text-2xl font-bold">Badge Removed</h1>
      <p className="text-muted-foreground">
        This badge has been taken down by the document owner.
        {reason && <span className="mt-2 block">Reason: {reason}</span>}
      </p>
    </div>
  );
}

function toViewStats(
  stats: BadgeStats,
  resolvedMetrics: ReturnType<typeof resolveDisplayMetrics>
): ViewStats {
  return {
    ai_percentage: resolvedMetrics.aiPercentage,
    external_paste_percentage: resolvedMetrics.externalPastePercentage,
    interaction_count: stats.interaction_count ?? 0,
    session_count: stats.session_count ?? 0,
    total_active_seconds: stats.total_active_seconds ?? 0,
    total_characters: resolvedMetrics.totalCharacters,
  };
}

function toViewAuditTrail(auditTrail: AuditTrail): ViewAuditTrail {
  return {
    interactions: auditTrail.ai_interactions ?? [],
    pasteEvents: auditTrail.paste_events ?? [],
    sessions: auditTrail.writing_sessions ?? [],
    revisions: auditTrail.revisions ?? [],
  };
}

