"use client";

import { useState, useCallback, useEffect, useRef } from "react";
import { useCompletion } from "@ai-sdk/react";
import { logAIInteraction } from "@/app/actions/ai-interactions";
import { Button } from "@/components/ui/button";

// freeform command palette for AI prompts
interface FreeformAIProps {
  documentId: string;
  provider: string;
  model?: string;
  getDocumentContent: () => Record<string, unknown>;
  onAIResponse?: (responseText: string) => void;
  onClose: () => void;
}

export function FreeformAI({
  documentId,
  provider,
  model,
  getDocumentContent,
  onAIResponse,
  onClose,
}: FreeformAIProps) {
  const [promptText, setPromptText] = useState("");
  const inputRef = useRef<HTMLInputElement>(null);

  const { completion, complete, isLoading, setCompletion } = useCompletion({
    api: "/api/ai/complete",
  });

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  useEffect(() => {
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
    };
    window.addEventListener("keydown", handleEscape);
    return () => window.removeEventListener("keydown", handleEscape);
  }, [onClose]);

  const handleSubmit = useCallback(
    async (e: React.FormEvent) => {
      e.preventDefault();
      if (!promptText.trim() || isLoading) return;

      const context = JSON.stringify(getDocumentContent());
      await complete(promptText, {
        body: {
          mode: "freeform",
          provider,
          model,
          context,
        },
      });
    },
    [promptText, isLoading, complete, provider, model, getDocumentContent]
  );

  const handleCopy = useCallback(async () => {
    if (!completion) return;
    await navigator.clipboard.writeText(completion);

    await logAIInteraction({
      documentId,
      mode: "freeform",
      prompt: promptText,
      response: completion,
      action: "accepted",
      provider,
      model: model ?? "",
    });

    onAIResponse?.(completion);

    setCompletion("");
    onClose();
  }, [
    completion,
    documentId,
    promptText,
    provider,
    model,
    setCompletion,
    onAIResponse,
    onClose,
  ]);

  const handleDismiss = useCallback(() => {
    if (completion) {
      void logAIInteraction({
        documentId,
        mode: "freeform",
        prompt: promptText,
        response: completion,
        action: "dismissed",
        provider,
        model: model ?? "",
      });
    }

    setCompletion("");
    onClose();
  }, [completion, documentId, promptText, provider, model, setCompletion, onClose]);

  return (
    <div
      className="fixed inset-0 z-50 flex items-start justify-center bg-black/50 pt-[20vh]"
      data-testid="freeform-ai-modal"
    >
      <div className="w-full max-w-lg rounded-lg border bg-background shadow-lg">
        <form onSubmit={handleSubmit} className="p-4">
          <input
            ref={inputRef}
            value={promptText}
            onChange={(e) => setPromptText(e.target.value)}
            placeholder="Ask AI anything about your document..."
            className="w-full rounded-md border px-3 py-2 text-sm"
            disabled={isLoading}
          />
        </form>

        {completion && (
          <div className="border-t p-4">
            <div className="mb-3 max-h-60 overflow-y-auto rounded-md bg-muted p-3 text-sm">
              {completion}
            </div>
            <div className="flex justify-end gap-2">
              <button
                onClick={handleDismiss}
                className="rounded-md border px-3 py-1 text-sm hover:bg-accent transition-colors duration-150"
              >
                Dismiss
              </button>
              <Button
                variant="provenance"
                size="sm"
                onClick={handleCopy}
              >
                Copy
              </Button>
            </div>
          </div>
        )}

        {isLoading && !completion && (
          <div className="border-t p-4 text-sm text-muted-foreground">
            Generating...
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import { useCompletion } from "@ai-sdk/react";
import type { Editor } from "@tiptap/react";
import { logAIInteraction } from "@/app/actions/ai-interactions";
import {
  createSourceId,
  getInlineAIErrorMessage,
  parseSuggestions,
  suggestionDeltaLabel,
} from "./inline-ai-utils";
import {
  InlineAIChooserStage,
  InlineAIToolbarStage,
} from "./InlineAIStages";

interface InlineAIProps {
  editor: Editor;
  documentId: string;
  provider: string;
  model?: string;
  selectedText: string;
  selectionFrom: number;
  selectionTo: number;
  anchorTop?: number;
  anchorRight?: number;
  onDismiss: () => void;
  onAIResponse?: (responseText: string) => void;
}

type Stage = "toolbar" | "choosing";

interface Choice {
  id: string;
  label: string;
  sublabel?: string;
  text: string;
  isOriginal: boolean;
}

function buildDualSuggestionPrompt(prompt: string) {
  return `${prompt}

Return exactly TWO distinct rewritten options for the selected text.
Do not include explanations.
Use this format exactly:
SUGGESTION 1:
<text>
---
SUGGESTION 2:
<text>`;
}

function getNextChoiceId(params: {
  choices: Choice[];
  selectedChoiceId: string;
  direction: "up" | "down";
}) {
  const { choices, selectedChoiceId, direction } = params;
  const index = choices.findIndex((choice) => choice.id === selectedChoiceId);
  if (index < 0) {
    return choices[0]?.id ?? selectedChoiceId;
  }

  const nextIndex =
    direction === "down"
      ? (index + 1) % choices.length
      : (index - 1 + choices.length) % choices.length;
  return choices[nextIndex].id;
}

export function InlineAI({
  editor,
  documentId,
  provider,
  model,
  selectedText,
  selectionFrom,
  selectionTo,
  anchorTop = 96,
  anchorRight = 24,
  onDismiss,
  onAIResponse,
}: InlineAIProps) {
  const [stage, setStage] = useState<Stage>("toolbar");
  const [promptText, setPromptText] = useState("");
  const [lastPrompt, setLastPrompt] = useState("");
  const [activeAction, setActiveAction] = useState("");
  const [selectedChoiceId, setSelectedChoiceId] = useState("original");
  const [error, setError] = useState<string | null>(null);

  const { completion, complete, isLoading, setCompletion, stop } = useCompletion({
    api: "/api/ai/complete",
    onError: (err) => {
      setError(getInlineAIErrorMessage(err.message || "AI request failed"));
    },
  });

  const choices = useMemo<Choice[]>(() => {
    if (!completion) return [];
    const [suggestionOne, suggestionTwo] = parseSuggestions(completion);

    return [
      {
        id: "original",
        label: "YOUR ORIGINAL",
        text: selectedText,
        isOriginal: true,
      },
      {
        id: "suggestion-1",
        label: "SUGGESTION 1",
        sublabel: suggestionDeltaLabel(selectedText, suggestionOne),
        text: suggestionOne,
        isOriginal: false,
      },
      {
        id: "suggestion-2",
        label: "SUGGESTION 2",
        sublabel: suggestionDeltaLabel(selectedText, suggestionTwo),
        text: suggestionTwo,
        isOriginal: false,
      },
    ];
  }, [completion, selectedText]);

  const handleSubmit = useCallback(
    async (prompt: string, actionName: string) => {
      setLastPrompt(prompt);
      setActiveAction(actionName);
      setError(null);
      setStage("choosing");
      setSelectedChoiceId("original");

      await complete(buildDualSuggestionPrompt(prompt), {
        body: {
          mode: "inline",
          provider,
          model,
          selectedText,
        },
      });
    },
    [complete, provider, model, selectedText]
  );

  const logRejectedCompletion = useCallback(
    (responseText: string) => {
      void logAIInteraction({
        documentId,
        mode: "inline",
        prompt: lastPrompt,
        selectedText,
        response: responseText,
        action: "rejected",
        provider,
        model: model ?? "",
        charactersInserted: 0,
      });
    },
    [documentId, lastPrompt, selectedText, provider, model]
  );

  const handleConfirm = useCallback(async () => {
    const selected = choices.find((choice) => choice.id === selectedChoiceId);
    if (!selected) return;

    if (selected.isOriginal) {
      if (completion) {
        logRejectedCompletion(completion);
      }
      setCompletion("");
      onDismiss();
      return;
    }

    const sourceId = createSourceId();

    await logAIInteraction({
      sourceId,
      documentId,
      mode: "inline",
      prompt: lastPrompt,
      selectedText,
      response: selected.text,
      action: "accepted",
      provider,
      model: model ?? "",
      charactersInserted: selected.text.length,
    });

    editor
      .chain()
      .focus()
      .insertContentAt({ from: selectionFrom, to: selectionTo }, [
        {
          type: "text",
          text: selected.text,
          marks: [
            {
              type: "origin",
              attrs: {
                type: "ai",
                sourceId,
                originalLength: selected.text.length,
                originalText: selected.text,
              },
            },
          ],
        },
      ])
      .run();

    onAIResponse?.(selected.text);
    setCompletion("");
    onDismiss();
  }, [
    choices,
    selectedChoiceId,
    completion,
    logRejectedCompletion,
    setCompletion,
    onDismiss,
    documentId,
    lastPrompt,
    selectedText,
    provider,
    model,
    editor,
    selectionFrom,
    selectionTo,
    onAIResponse,
  ]);

  const handleDismiss = useCallback(() => {
    if (isLoading) stop();
    if (completion) {
      logRejectedCompletion(completion);
    }
    setCompletion("");
    onDismiss();
  }, [isLoading, stop, completion, logRejectedCompletion, setCompletion, onDismiss]);

  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        event.preventDefault();
        handleDismiss();
        return;
      }

      if (stage !== "choosing" || choices.length === 0) {
        return;
      }

      if (event.key === "ArrowUp" || event.key === "ArrowDown") {
        event.preventDefault();
        const direction = event.key === "ArrowDown" ? "down" : "up";
        setSelectedChoiceId(
          getNextChoiceId({
            choices,
            selectedChoiceId,
            direction,
          })
        );
      }

      if (event.key === "Enter" && !isLoading) {
        event.preventDefault();
        void handleConfirm();
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [stage, choices, selectedChoiceId, isLoading, handleConfirm, handleDismiss]);

  if (stage === "toolbar") {
    return (
      <InlineAIToolbarStage
        anchorTop={anchorTop}
        anchorRight={anchorRight}
        selectedText={selectedText}
        promptText={promptText}
        onPromptTextChange={setPromptText}
        onSubmit={handleSubmit}
        onDismiss={handleDismiss}
      />
    );
  }

  return (
    <InlineAIChooserStage
      anchorTop={anchorTop}
      anchorRight={anchorRight}
      selectedText={selectedText}
      activeAction={activeAction}
      choices={choices}
      selectedChoiceId={selectedChoiceId}
      isLoading={isLoading}
      error={error}
      lastPrompt={lastPrompt}
      onRetry={() => {
        if (lastPrompt) {
          void handleSubmit(lastPrompt, activeAction);
        }
      }}
      onSelectChoice={setSelectedChoiceId}
      onConfirm={() => {
        void handleConfirm();
      }}
      onDismiss={handleDismiss}
    />
  );
}

"use client";

import { Check, Sparkles } from "lucide-react";
import { Button } from "@/components/ui/button";
import { TrackChangesDiff } from "./TrackChangesDiff";
import { PRESETS, changeRatio, wordCount } from "./inline-ai-utils";

interface Choice {
  id: string;
  label: string;
  sublabel?: string;
  text: string;
  isOriginal: boolean;
}

const DIFF_THRESHOLD = 0.25;

interface InlineAIToolbarStageProps {
  anchorTop: number;
  anchorRight: number;
  selectedText: string;
  promptText: string;
  onPromptTextChange: (value: string) => void;
  onSubmit: (prompt: string, actionName: string) => void;
  onDismiss: () => void;
}

export function InlineAIToolbarStage({
  anchorTop,
  anchorRight,
  selectedText,
  promptText,
  onPromptTextChange,
  onSubmit,
  onDismiss,
}: InlineAIToolbarStageProps) {
  const selectionWordCount = wordCount(selectedText);

  return (
    <div
      className="floating-toolbar absolute z-50 w-[calc(100%-2rem)] max-w-md rounded-lg border bg-background p-3 shadow-lg"
      style={{ top: `${anchorTop + 36}px`, right: `${anchorRight}px` }}
      data-testid="inline-ai-toolbar"
    >
      <div className="mb-2 flex items-center gap-2 text-xs text-muted-foreground">
        <Sparkles className="h-3.5 w-3.5 text-violet-500" />
        <span>
          Selection · {selectionWordCount} word{selectionWordCount !== 1 ? "s" : ""}
        </span>
      </div>

      <div className="mb-2 flex flex-wrap gap-1">
        {PRESETS.map((preset) => (
          <Button
            key={preset.label}
            variant="outline"
            size="xs"
            onClick={() => onSubmit(preset.prompt, preset.label)}
          >
            {preset.label}
          </Button>
        ))}
      </div>

      <form
        onSubmit={(event) => {
          event.preventDefault();
          if (promptText.trim()) onSubmit(promptText, "Custom");
        }}
      >
        <input
          value={promptText}
          onChange={(event) => onPromptTextChange(event.target.value)}
          placeholder="Custom prompt..."
          className="w-full rounded-md border px-2 py-1 text-sm"
          autoFocus
        />
      </form>

      <div className="mt-2 flex justify-end">
        <button
          onClick={onDismiss}
          className="text-xs text-muted-foreground transition-colors duration-150 hover:text-foreground"
        >
          Cancel
        </button>
      </div>
    </div>
  );
}

interface InlineAIChooserStageProps {
  anchorTop: number;
  anchorRight: number;
  selectedText: string;
  activeAction: string;
  choices: Choice[];
  selectedChoiceId: string;
  isLoading: boolean;
  error: string | null;
  lastPrompt: string;
  onRetry: () => void;
  onSelectChoice: (choiceId: string) => void;
  onConfirm: () => void;
  onDismiss: () => void;
}

function ChoiceCard({
  choice,
  selectedText,
  isSelected,
  onSelect,
}: {
  choice: Choice;
  selectedText: string;
  isSelected: boolean;
  onSelect: () => void;
}) {
  return (
    <button
      key={choice.id}
      onClick={onSelect}
      className={`relative w-full rounded-lg border-2 p-3 text-left text-sm transition-colors ${
        isSelected
          ? "border-provenance-500 bg-provenance-500/5"
          : "border-border hover:border-violet-300"
      }`}
      data-testid={`choice-${choice.id}`}
    >
      {isSelected && (
        <div className="absolute right-2 top-2 flex h-5 w-5 items-center justify-center rounded-full bg-provenance-500 text-white">
          <Check className="h-3 w-3" />
        </div>
      )}

      <div className="mb-1 flex items-center gap-2">
        <span
          className={`text-xs font-semibold uppercase tracking-wider ${
            choice.isOriginal ? "text-muted-foreground" : "text-violet-500"
          }`}
        >
          {choice.label}
        </span>
        {choice.sublabel && (
          <span className="text-xs text-muted-foreground">
            {choice.sublabel}
          </span>
        )}
      </div>

      <div className="text-foreground">
        {choice.isOriginal || changeRatio(selectedText, choice.text) >= DIFF_THRESHOLD ? (
          <span className="whitespace-pre-wrap">{choice.text}</span>
        ) : (
          <TrackChangesDiff original={selectedText} suggestion={choice.text} />
        )}
      </div>
    </button>
  );
}

export function InlineAIChooserStage({
  anchorTop,
  anchorRight,
  selectedText,
  activeAction,
  choices,
  selectedChoiceId,
  isLoading,
  error,
  lastPrompt,
  onRetry,
  onSelectChoice,
  onConfirm,
  onDismiss,
}: InlineAIChooserStageProps) {
  const sentenceCount = selectedText.split(/[.!?]+/).filter((s) => s.trim()).length;

  return (
    <div
      className="floating-toolbar absolute z-50 flex w-[calc(100%-2rem)] max-w-lg flex-col overflow-hidden rounded-xl border bg-background shadow-lg"
      style={{
        top: `${anchorTop + 36}px`,
        right: `${anchorRight}px`,
        maxHeight: `calc(100% - ${anchorTop + 36}px - 8px)`,
      }}
      data-testid="inline-ai-chooser"
    >
      <div className="flex shrink-0 items-center justify-between border-b bg-muted px-4 py-2">
        <div className="flex items-center gap-2 text-sm">
          <Sparkles className="h-3.5 w-3.5 text-violet-500" />
          <span className="font-medium">{activeAction}</span>
          <span className="text-muted-foreground">
            · Selection · {sentenceCount} sentence{sentenceCount !== 1 ? "s" : ""}
          </span>
        </div>
      </div>

      <div className="min-h-0 space-y-2 overflow-y-auto p-3">
        {isLoading && choices.length === 0 && (
          <div className="py-4 text-center text-sm text-muted-foreground">
            Generating suggestion...
          </div>
        )}

        {error && !isLoading && (
          <div className="rounded-md bg-destructive/10 p-2 text-sm text-destructive">
            <p>{error}</p>
            <button
              onClick={() => lastPrompt && onRetry()}
              className="mt-1 font-medium underline hover:no-underline"
            >
              Retry
            </button>
          </div>
        )}

        {choices.map((choice) => (
          <ChoiceCard
            key={choice.id}
            choice={choice}
            selectedText={selectedText}
            isSelected={selectedChoiceId === choice.id}
            onSelect={() => onSelectChoice(choice.id)}
          />
        ))}
      </div>

      <div className="flex shrink-0 items-center justify-between border-t bg-muted px-4 py-2">
        <span className="text-xs text-muted-foreground">
          <kbd className="rounded border px-1">↑↓</kbd> navigate ·{" "}
          <kbd className="rounded border px-1">Enter</kbd> confirm ·{" "}
          <kbd className="rounded border px-1">Esc</kbd> dismiss
        </span>
        <div className="flex items-center gap-2">
          <Button variant="ghost" size="sm" onClick={onDismiss}>
            Cancel
          </Button>
          <Button
            variant="provenance"
            size="sm"
            onClick={onConfirm}
            disabled={isLoading || choices.length === 0}
          >
            Confirm Selection
          </Button>
        </div>
      </div>
    </div>
  );
}

"use client";

interface SaveIndicatorProps {
  status: "idle" | "saving" | "saved" | "error";
  onRetry?: () => void;
}

export function SaveIndicator({ status, onRetry }: SaveIndicatorProps) {
  if (status === "idle") return null;

  const labels = {
    saving: "Saving...",
    saved: "Saved",
    error: "Save failed",
  };

  const colors = {
    saving: "text-muted-foreground",
    saved: "text-muted-foreground",
    error: "text-destructive",
  };

  return (
    <span className={`text-sm ${colors[status]}`} data-testid="save-indicator">
      {labels[status]}
      {status === "error" && onRetry && (
        <button
          onClick={onRetry}
          className="ml-1 font-medium underline hover:no-underline"
        >
          retry
        </button>
      )}
    </span>
  );
}

"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { AuditTimeline } from "@/components/verify/AuditTimeline";
import { X } from "lucide-react";

interface TimelineModalProps {
  documentId: string;
  isOpen: boolean;
  onClose: () => void;
}

interface TimelineData {
  interactions: Array<{
    mode: string;
    prompt: string;
    response: string;
    action: string;
    createdAt: string | Date | null;
  }>;
  pasteEvents: Array<{
    sourceType: string;
    characterCount: number;
    createdAt: string | Date | null;
  }>;
  sessions: Array<{
    startedAt: string | Date | null;
    endedAt: string | Date | null;
    activeSeconds: number | null;
  }>;
  revisions: Array<{
    trigger: string;
    createdAt: string | Date | null;
  }>;
}

export function TimelineModal({ documentId, isOpen, onClose }: TimelineModalProps) {
  const [data, setData] = useState<TimelineData | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!isOpen) return;
    let cancelled = false;
    queueMicrotask(() => {
      if (!cancelled) setLoading(true);
    });
    fetch(`/api/documents/${documentId}/timeline`)
      .then((res) => (res.ok ? res.json() : null))
      .then((d) => { if (!cancelled) setData(d); })
      .catch(() => { if (!cancelled) setData(null); })
      .finally(() => { if (!cancelled) setLoading(false); });
    return () => { cancelled = true; };
  }, [isOpen, documentId]);

  const handleKeyDown = useCallback(
    (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
    },
    [onClose]
  );

  useEffect(() => {
    if (!isOpen) return;
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, handleKeyDown]);

  const dialogRef = useRef<HTMLDivElement>(null);

  // Focus trap + auto-focus close button on open
  useEffect(() => {
    if (!isOpen || !dialogRef.current) return;
    const dialog = dialogRef.current;
    const focusable = dialog.querySelectorAll<HTMLElement>(
      'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
    );
    const first = focusable[0];
    const last = focusable[focusable.length - 1];
    first?.focus();

    const trapFocus = (e: KeyboardEvent) => {
      if (e.key !== "Tab") return;
      if (e.shiftKey) {
        if (document.activeElement === first) {
          e.preventDefault();
          last?.focus();
        }
      } else {
        if (document.activeElement === last) {
          e.preventDefault();
          first?.focus();
        }
      }
    };
    dialog.addEventListener("keydown", trapFocus);
    return () => dialog.removeEventListener("keydown", trapFocus);
  }, [isOpen]);

  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50"
      onClick={(e) => {
        if (e.target === e.currentTarget) onClose();
      }}
      data-testid="timeline-modal"
      role="dialog"
      aria-modal="true"
      aria-label="Document History"
      ref={dialogRef}
    >
      <div className="relative max-h-[80vh] w-full max-w-2xl overflow-auto rounded-lg border bg-background p-6 shadow-lg">
        <div className="mb-4 flex items-center justify-between">
          <h2 className="text-lg font-semibold" id="timeline-modal-title">Document History</h2>
          <button
            onClick={onClose}
            className="rounded-md p-1 hover:bg-accent"
            aria-label="Close"
          >
            <X className="h-5 w-5" />
          </button>
        </div>

        {loading && (
          <p className="py-8 text-center text-sm text-muted-foreground">
            Loading timeline...
          </p>
        )}

        {!loading && data && (
          <AuditTimeline
            interactions={data.interactions}
            pasteEvents={data.pasteEvents}
            sessions={data.sessions}
            revisions={data.revisions}
            showBadgeLandmark={false}
          />
        )}

        {!loading && !data && (
          <p className="py-8 text-center text-sm text-muted-foreground">
            Failed to load timeline.
          </p>
        )}
      </div>
    </div>
  );
}

