"use client";

import { useState, useCallback, useRef, useEffect, useMemo } from "react";
import { useChat } from "@ai-sdk/react";
import { DefaultChatTransport } from "ai";
import type { UIMessage } from "ai";
import { ChatHeader } from "./ChatHeader";
import { ChatMessage } from "./ChatMessage";
import { ChatInput } from "./ChatInput";
import { ChatEmptyState } from "./ChatEmptyState";
import {
  getChatThread,
  saveChatThread,
} from "@/app/actions/chat-threads";

interface ThreadSummary {
  id: string;
  title: string;
  messageCount: number | null;
  updatedAt: Date | null;
}

interface ChatPanelProps {
  documentId: string;
  provider: string;
  model?: string;
  getDocumentContent: () => Record<string, unknown>;
  initialThreads: ThreadSummary[];
  onAssistantResponse?: (responseText: string) => void;
  onClose: () => void;
}

function extractPlainTextFromContent(
  content: Record<string, unknown>
): string {
  const extract = (node: Record<string, unknown>): string => {
    if (node.text && typeof node.text === "string") return node.text;
    if (Array.isArray(node.content)) {
      return node.content.map((child) => extract(child)).join("");
    }
    return "";
  };
  return extract(content);
}

function getTextFromMessage(message: UIMessage): string {
  return message.parts
    .filter((p): p is { type: "text"; text: string } => p.type === "text")
    .map((p) => p.text)
    .join("");
}

export function ChatPanel({
  documentId,
  provider,
  model,
  getDocumentContent,
  initialThreads,
  onAssistantResponse,
  onClose,
}: ChatPanelProps) {
  const [threads, setThreads] = useState<ThreadSummary[]>(initialThreads);
  const [activeThreadId, setActiveThreadId] = useState<string | null>(null);
  const [selectedProvider, setSelectedProvider] = useState(provider);
  const [selectedModel, setSelectedModel] = useState(model);
  const [inputValue, setInputValue] = useState("");
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const startTimeRef = useRef<number>(0);
  const streamThreadIdRef = useRef<string | null>(null);
  const savingRef = useRef(false);

  const getDocumentContext = useCallback(
    () => extractPlainTextFromContent(getDocumentContent()),
    [getDocumentContent]
  );

  const wordCount = useMemo(
    () => getDocumentContext().split(/\s+/).filter(Boolean).length,
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [getDocumentContent]
  );

  const handleModelChange = useCallback(
    (newProvider: string, newModel: string) => {
      setSelectedProvider(newProvider);
      setSelectedModel(newModel);
    },
    []
  );

  const transportRef = useRef({ getDocumentContext, activeThreadId, selectedProvider, selectedModel });
  transportRef.current = { getDocumentContext, activeThreadId, selectedProvider, selectedModel };

  const transport = useMemo(
    () =>
      new DefaultChatTransport({
        api: "/api/chat",
        prepareSendMessagesRequest: ({ messages: msgs, id }) => ({
          body: {
            id,
            messages: msgs,
            documentContext: transportRef.current.getDocumentContext(),
            ...(transportRef.current.activeThreadId
              ? { threadId: transportRef.current.activeThreadId }
              : {}),
            provider: transportRef.current.selectedProvider,
            model: transportRef.current.selectedModel,
          },
        }),
      }),
    []
  );

  const {
    messages,
    setMessages,
    sendMessage,
    status,
    stop,
  } = useChat({
    transport,
    experimental_throttle: 50,
    onFinish: async ({ message, messages: allMessages }) => {
      const threadId = streamThreadIdRef.current;
      const assistantText = getTextFromMessage(message).trim();
      if (assistantText) {
        onAssistantResponse?.(assistantText);
      }

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const metadata = message.metadata as Record<string, any> | undefined;
      const elapsed = Math.round((Date.now() - startTimeRef.current) / 60000);

      const firstUserMsg = allMessages.find((m) => m.role === "user");
      const title = firstUserMsg
        ? getTextFromMessage(firstUserMsg).slice(0, 50) || "New conversation"
        : "New conversation";

      if (!threadId && savingRef.current) return;
      savingRef.current = true;

      try {
        const saved = await saveChatThread({
          documentId,
          threadId: threadId ?? undefined,
          title,
          messages: allMessages,
          messageCount: allMessages.length,
          summary: {
            messageCount: allMessages.length,
            durationMinutes: elapsed,
            category: "ask",
            provider: metadata?.provider ?? selectedProvider,
            model: metadata?.model ?? selectedModel ?? "",
            ...(metadata?.tokenCount
              ? { tokenCount: metadata.tokenCount }
              : {}),
          },
        });

        if (!threadId && saved) {
          setActiveThreadId(saved.id);
          streamThreadIdRef.current = saved.id;
          setThreads((prev) => [
            {
              id: saved.id,
              title: saved.title,
              messageCount: saved.messageCount,
              updatedAt: saved.updatedAt,
            },
            ...prev,
          ]);
        } else if (saved) {
          setThreads((prev) =>
            prev.map((t) =>
              t.id === saved.id
                ? {
                    ...t,
                    title: saved.title,
                    messageCount: saved.messageCount,
                    updatedAt: saved.updatedAt,
                  }
                : t
            )
          );
        }
      } catch (err) {
        console.error("[ChatPanel] Failed to save thread:", err);
      } finally {
        savingRef.current = false;
      }
    },
  });

  const isStreaming = status === "streaming";

  useEffect(() => {
    if (initialThreads.length === 0) {
      if (!startTimeRef.current) startTimeRef.current = Date.now();
      return;
    }

    let cancelled = false;
    const latestThreadId = initialThreads[0]?.id;
    if (!latestThreadId) return;

    void (async () => {
      try {
        const thread = await getChatThread(latestThreadId);
        if (cancelled) return;
        setActiveThreadId(thread.id);
        streamThreadIdRef.current = thread.id;
        setMessages((thread.messages ?? []) as UIMessage[]);
        startTimeRef.current = Date.now();
      } catch (err) {
        if (!cancelled) {
          console.error("[ChatPanel] Failed to restore latest thread:", err);
        }
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [initialThreads, setMessages]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleThreadSelect = useCallback(
    async (threadId: string | null) => {
      if (isStreaming) stop();

      if (!threadId) {
        setActiveThreadId(null);
        streamThreadIdRef.current = null;
        setMessages([]);
        startTimeRef.current = Date.now();
        return;
      }

      try {
        const thread = await getChatThread(threadId);
        setActiveThreadId(thread.id);
        streamThreadIdRef.current = thread.id;
        setMessages((thread.messages ?? []) as UIMessage[]);
        startTimeRef.current = Date.now();
      } catch (err) {
        console.error("[ChatPanel] Failed to load thread:", err);
      }
    },
    [setMessages, isStreaming, stop]
  );

  const handleNewThread = useCallback(() => {
    if (isStreaming) stop();
    setActiveThreadId(null);
    streamThreadIdRef.current = null;
    setMessages([]);
    setInputValue("");
    startTimeRef.current = Date.now();
  }, [setMessages, isStreaming, stop]);

  const handleSubmit = useCallback(() => {
    if (!inputValue.trim()) return;
    const text = inputValue;
    setInputValue("");
    streamThreadIdRef.current = activeThreadId;
    startTimeRef.current = startTimeRef.current || Date.now();
    sendMessage({ text });
  }, [inputValue, sendMessage, activeThreadId]);

  const handleSuggestionClick = useCallback(
    (suggestion: string) => {
      setInputValue("");
      streamThreadIdRef.current = activeThreadId;
      startTimeRef.current = Date.now();
      sendMessage({ text: suggestion });
    },
    [sendMessage, activeThreadId]
  );

  return (
    <div className="flex h-full flex-col bg-muted">
      <ChatHeader
        threads={threads}
        activeThreadId={activeThreadId}
        onThreadSelect={handleThreadSelect}
        onNewThread={handleNewThread}
        onClose={onClose}
        selectedProvider={selectedProvider}
        selectedModel={selectedModel}
        onModelChange={handleModelChange}
      />

      <div className="flex-1 overflow-y-auto px-4 py-5">
        {messages.length === 0 ? (
          <ChatEmptyState onSuggestionClick={handleSuggestionClick} />
        ) : (
          <div className="flex flex-col gap-4">
            {messages.map((message, i) => (
              <ChatMessage
                key={message.id ?? i}
                message={message}
                isStreaming={
                  isStreaming && i === messages.length - 1 && message.role === "assistant"
                }
              />
            ))}
            <div ref={messagesEndRef} />
          </div>
        )}
      </div>

      <ChatInput
        value={inputValue}
        onChange={setInputValue}
        onSubmit={handleSubmit}
        onStop={stop}
        isStreaming={isStreaming}
        wordCount={wordCount}
        hasMessages={messages.length > 0}
      />
    </div>
  );
}

export interface TextSelection {
  text: string;
  from: number;
  to: number;
}

export function areSelectionsEqual(
  current: TextSelection | null,
  next: TextSelection | null
): boolean {
  if (current === next) return true;
  if (!current || !next) return false;
  return (
    current.text === next.text &&
    current.from === next.from &&
    current.to === next.to
  );
}

export function hasDocumentText(content: unknown): boolean {
  if (!content || typeof content !== "object") return false;
  const stack: unknown[] = [content];

  while (stack.length > 0) {
    const node = stack.pop();
    if (!node || typeof node !== "object") continue;
    const record = node as { text?: unknown; content?: unknown[] };

    if (typeof record.text === "string" && record.text.trim().length > 0) {
      return true;
    }

    if (Array.isArray(record.content)) {
      stack.push(...record.content);
    }
  }

  return false;
}

function timelineStateKey(documentId: string): string {
  return `provenance:editor:${documentId}:timeline-open`;
}

export function readTimelineOpenState(documentId: string): boolean {
  if (typeof window === "undefined") return false;
  return window.localStorage.getItem(timelineStateKey(documentId)) === "1";
}

export function writeTimelineOpenState(documentId: string, isOpen: boolean) {
  if (typeof window === "undefined") return;
  window.localStorage.setItem(timelineStateKey(documentId), isOpen ? "1" : "0");
}

export const PRESETS = [
  { label: "Improve", prompt: "Improve this text while keeping the same meaning" },
  { label: "Simplify", prompt: "Simplify this text to be more concise and clear" },
  { label: "Expand", prompt: "Expand on this text with more detail" },
  { label: "Fix", prompt: "Fix grammar, spelling, and clarity issues in this text" },
  { label: "More formal", prompt: "Rewrite this text in a more formal tone" },
  { label: "More casual", prompt: "Rewrite this text in a more casual tone" },
];

export function wordCount(text: string): number {
  return text.split(/\s+/).filter(Boolean).length;
}

export function changeRatio(original: string, suggestion: string): number {
  const origWords = original.split(/\s+/).filter(Boolean);
  const suggWords = suggestion.split(/\s+/).filter(Boolean);
  const maxLen = Math.max(origWords.length, suggWords.length);
  if (maxLen === 0) return 0;

  const m = origWords.length;
  const n = suggWords.length;
  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] =
        origWords[i - 1] === suggWords[j - 1]
          ? dp[i - 1][j - 1] + 1
          : Math.max(dp[i - 1][j], dp[i][j - 1]);
    }
  }

  const common = dp[m][n];
  return 1 - common / maxLen;
}

export function createSourceId(): string {
  if (globalThis.crypto?.randomUUID) {
    return globalThis.crypto.randomUUID();
  }

  return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, (char) => {
    const rand = Math.floor(Math.random() * 16);
    const value = char === "x" ? rand : (rand & 0x3) | 0x8;
    return value.toString(16);
  });
}

function cleanSuggestionText(text: string): string {
  return text
    .replace(/^\s*(SUGGESTION|OPTION)\s*\d+\s*:\s*/i, "")
    .trim();
}

export function parseSuggestions(rawCompletion: string): [string, string] {
  const completion = rawCompletion.trim();
  if (!completion) return ["", ""];

  const delimiterMatch = completion
    .split(/\n-{3,}\n/)
    .map((part) => cleanSuggestionText(part))
    .filter(Boolean);
  if (delimiterMatch.length >= 2) {
    return [delimiterMatch[0], delimiterMatch[1]];
  }

  const explicitMatch = completion.match(
    /SUGGESTION\s*1\s*:\s*([\s\S]*?)\n+\s*SUGGESTION\s*2\s*:\s*([\s\S]*)/i
  );
  if (explicitMatch) {
    return [
      cleanSuggestionText(explicitMatch[1]),
      cleanSuggestionText(explicitMatch[2]),
    ];
  }

  const blocks = completion
    .split(/\n{2,}/)
    .map((part) => cleanSuggestionText(part))
    .filter(Boolean);
  if (blocks.length >= 2) {
    return [blocks[0], blocks[1]];
  }

  return [cleanSuggestionText(completion), cleanSuggestionText(completion)];
}

export function suggestionDeltaLabel(
  originalText: string,
  suggestionText: string
): string | undefined {
  const originalWords = wordCount(originalText);
  const suggestionWords = wordCount(suggestionText);
  const diff = originalWords - suggestionWords;
  if (diff > 0) return `· ${diff} fewer word${diff !== 1 ? "s" : ""}`;
  if (diff < 0) {
    const magnitude = Math.abs(diff);
    return `· ${magnitude} more word${magnitude !== 1 ? "s" : ""}`;
  }
  return undefined;
}

export function getInlineAIErrorMessage(message: string): string {
  if (message.includes("429") || message.includes("rate limit")) {
    return "Rate limit exceeded. Please wait a moment and retry.";
  }
  if (message.includes("502") || message.includes("503")) {
    return "AI provider is temporarily unavailable. Please retry.";
  }
  return "Something went wrong. Please try again.";
}

import type { Editor } from "@tiptap/react";

export interface TriggerPosition {
  top: number;
  left: number;
  right: number;
}

export function resolveTriggerPosition(params: {
  editor: Editor;
  main: HTMLElement;
  proseArea: HTMLDivElement | null;
  position?: number;
}): TriggerPosition {
  const { editor, main, proseArea, position } = params;
  const mainRect = main.getBoundingClientRect();
  const proseRect = proseArea?.getBoundingClientRect();

  const iconSize = 32;
  const fallbackWidth = main.clientWidth || 1200;
  const fallbackHeight = main.clientHeight || 800;
  const targetPosition = Math.max(1, position ?? editor.state.selection.from);
  const cursorCoords = editor.view.coordsAtPos(targetPosition);

  const minTop = 56;
  const maxTop = Math.max(minTop, fallbackHeight - iconSize - 8);
  const top = Math.min(
    maxTop,
    Math.max(minTop, cursorCoords.top - mainRect.top - 4)
  );

  const rightMarginAnchor = proseRect?.right
    ? proseRect.right - mainRect.left + 8
    : fallbackWidth - iconSize - 12;
  const left = Math.min(
    fallbackWidth - iconSize - 8,
    Math.max(8, rightMarginAnchor)
  );
  const right = Math.max(8, fallbackWidth - left - iconSize);

  return { top, left, right };
}

"use client";

import { useState, useTransition } from "react";
import { providers } from "@/lib/ai/providers";
import { updateUserPreferences } from "@/app/actions/user";

interface AISettingsProps {
  currentProvider: string;
  currentModel: string | null;
}

export function AISettings({ currentProvider, currentModel }: AISettingsProps) {
  const [provider, setProvider] = useState(currentProvider || "anthropic");
  const [model, setModel] = useState(
    currentModel || providers[currentProvider]?.defaultModel || ""
  );
  const [isPending, startTransition] = useTransition();
  const [saved, setSaved] = useState(false);

  const selectedProvider = providers[provider];
  const availableModels = selectedProvider?.models ?? [];

  const handleProviderChange = (newProvider: string) => {
    setProvider(newProvider);
    const p = providers[newProvider];
    setModel(p?.defaultModel || "");
    setSaved(false);
  };

  const handleSave = () => {
    startTransition(async () => {
      await updateUserPreferences({ aiProvider: provider, aiModel: model });
      setSaved(true);
      setTimeout(() => setSaved(false), 2000);
    });
  };

  return (
    <div className="space-y-4">
      <h3 className="text-lg font-medium">AI Provider Settings</h3>

      <div className="space-y-2">
        <label className="text-sm font-medium">Provider</label>
        <select
          value={provider}
          onChange={(e) => handleProviderChange(e.target.value)}
          className="w-full rounded-md border px-3 py-2 text-sm"
        >
          {Object.values(providers).map((p) => (
            <option key={p.id} value={p.id}>
              {p.name}
            </option>
          ))}
        </select>
      </div>

      <div className="space-y-2">
        <label className="text-sm font-medium">Model</label>
        <select
          value={model}
          onChange={(e) => {
            setModel(e.target.value);
            setSaved(false);
          }}
          className="w-full rounded-md border px-3 py-2 text-sm"
        >
          {availableModels.map((m) => (
            <option key={m.id} value={m.id}>
              {m.name} ({m.tier})
            </option>
          ))}
        </select>
      </div>

      <button
        onClick={handleSave}
        disabled={isPending}
        className="rounded-md bg-primary px-4 py-2 text-sm text-primary-foreground hover:bg-primary/90 disabled:opacity-50"
      >
        {isPending ? "Saving..." : saved ? "Saved" : "Save Preferences"}
      </button>
    </div>
  );
}

