"use client";

interface MinimapEvent {
  type: "writing" | "ai" | "paste";
  timestamp: string | Date | null;
}

interface TimelineMinimapProps {
  interactions: Array<{ createdAt: string | Date | null }>;
  pasteEvents: Array<{ createdAt: string | Date | null }>;
  sessions: Array<{
    startedAt: string | Date | null;
    endedAt: string | Date | null;
  }>;
}

const COLORS = {
  writing: "bg-emerald-500",
  ai: "bg-violet-500",
  paste: "bg-orange-500",
};

function buildTimelineEvents({
  interactions,
  pasteEvents,
  sessions,
}: TimelineMinimapProps): MinimapEvent[] {
  const events: MinimapEvent[] = [];

  for (const session of sessions) {
    if (session.startedAt) {
      events.push({ type: "writing", timestamp: session.startedAt });
    }
  }

  for (const interaction of interactions) {
    if (interaction.createdAt) {
      events.push({ type: "ai", timestamp: interaction.createdAt });
    }
  }

  for (const paste of pasteEvents) {
    if (paste.createdAt) {
      events.push({ type: "paste", timestamp: paste.createdAt });
    }
  }

  return events;
}

function sortEventsByTimestamp(events: MinimapEvent[]) {
  return [...events].sort((a, b) => {
    const ta = a.timestamp ? new Date(a.timestamp).getTime() : 0;
    const tb = b.timestamp ? new Date(b.timestamp).getTime() : 0;
    return ta - tb;
  });
}

function buildBars(events: MinimapEvent[]) {
  const minTime = new Date(events[0].timestamp!).getTime();
  const maxTime = new Date(events[events.length - 1].timestamp!).getTime();
  const range = maxTime - minTime || 1;

  return events.map((event, index) => {
    const start = ((new Date(event.timestamp!).getTime() - minTime) / range) * 100;
    const end =
      index < events.length - 1
        ? ((new Date(events[index + 1].timestamp!).getTime() - minTime) / range) *
          100
        : 100;

    return {
      type: event.type,
      width: Math.max(end - start, 1),
    };
  });
}

function formatDateLabel(timestamp: string | Date | null) {
  return new Date(timestamp!).toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
  });
}

export function TimelineMinimap({ interactions, pasteEvents, sessions }: TimelineMinimapProps) {
  const events = buildTimelineEvents({ interactions, pasteEvents, sessions });

  if (events.length === 0) return null;

  const sortedEvents = sortEventsByTimestamp(events);
  const bars = buildBars(sortedEvents);
  const startDate = formatDateLabel(sortedEvents[0].timestamp);
  const endDate = formatDateLabel(sortedEvents[sortedEvents.length - 1].timestamp);

  return (
    <div data-testid="timeline-minimap">
      {/* Bar */}
      <div className="flex h-3 w-full overflow-hidden rounded-full">
        {bars.map((bar, i) => (
          <div
            key={i}
            className={COLORS[bar.type]}
            style={{ width: `${bar.width}%` }}
          />
        ))}
      </div>

      {/* Date labels */}
      <div className="mt-1 flex justify-between text-xs text-muted-foreground">
        <span>{startDate}</span>
        <span>{endDate}</span>
      </div>

      {/* Legend */}
      <div className="mt-2 flex gap-4 text-xs text-muted-foreground">
        <span className="flex items-center gap-1">
          <span className="inline-block h-2 w-2 rounded-full bg-emerald-500" />
          Writing
        </span>
        <span className="flex items-center gap-1">
          <span className="inline-block h-2 w-2 rounded-full bg-violet-500" />
          AI
        </span>
        <span className="flex items-center gap-1">
          <span className="inline-block h-2 w-2 rounded-full bg-orange-500" />
          Paste
        </span>
      </div>
    </div>
  );
}

import { Extension } from "@tiptap/core";
import { Plugin, PluginKey } from "@tiptap/pm/state";

type ActivationGesture = Pick<MouseEvent, "metaKey" | "ctrlKey">;

export interface EditorInteractionPolicyOptions {
  interactiveSelectors: readonly string[];
  isExplicitActivationGesture: (event: ActivationGesture) => boolean;
}

export const editorInteractionPolicyKey = new PluginKey("editorInteractionPolicy");
export const DEFAULT_INTERACTIVE_SELECTORS = [
  "a[href]",
  "[data-editor-interactive='true']",
] as const;

export function isExplicitActivationGesture(
  event: ActivationGesture
): boolean {
  return event.metaKey || event.ctrlKey;
}

export function buildInteractiveSelector(selectors: readonly string[]): string {
  return selectors
    .map((selector) => selector.trim())
    .filter(Boolean)
    .join(",");
}

function resolveEventTargetElement(target: EventTarget | null): Element | null {
  if (target instanceof Element) return target;
  if (target instanceof Node) return target.parentElement;
  return null;
}

export function shouldSuppressInteractiveClick({
  target,
  interactiveSelector,
  event,
  isEditable,
  isExplicitActivationGesture: allowActivation,
}: {
  target: EventTarget | null;
  interactiveSelector: string;
  event: ActivationGesture;
  isEditable: boolean;
  isExplicitActivationGesture: (event: ActivationGesture) => boolean;
}): boolean {
  if (!isEditable || !interactiveSelector) return false;
  const targetElement = resolveEventTargetElement(target);
  if (!targetElement) return false;

  const interactiveTarget = targetElement.closest(interactiveSelector);
  if (!interactiveTarget) return false;

  return !allowActivation(event);
}

export const EditorInteractionPolicy = Extension.create<EditorInteractionPolicyOptions>(
  {
    name: "editorInteractionPolicy",

    addOptions() {
      return {
        interactiveSelectors: DEFAULT_INTERACTIVE_SELECTORS,
        isExplicitActivationGesture,
      };
    },

    addProseMirrorPlugins() {
      const interactiveSelector = buildInteractiveSelector(
        this.options.interactiveSelectors
      );
      const allowActivation = this.options.isExplicitActivationGesture;

      return [
        new Plugin({
          key: editorInteractionPolicyKey,
          props: {
            handleDOMEvents: {
              click(view, event) {
                if (!(event instanceof MouseEvent)) return false;

                const shouldSuppress = shouldSuppressInteractiveClick({
                  target: event.target,
                  interactiveSelector,
                  event,
                  isEditable: view.editable,
                  isExplicitActivationGesture: allowActivation,
                });

                if (!shouldSuppress) return false;
                event.preventDefault();
                // Let ProseMirror continue processing the click so caret/selection still works.
                return false;
              },
            },
          },
        }),
      ];
    },
  }
);

import { Mark, mergeAttributes } from "@tiptap/core";

export const OriginMark = Mark.create({
  name: "origin",

  addAttributes() {
    return {
      type: { default: "human" },
      sourceId: { default: null },
      originalLength: { default: null },
      originalText: { default: null },
    };
  },

  renderHTML({ HTMLAttributes }) {
    const originType = HTMLAttributes.type as string;
    const cssClass =
      originType === "ai"
        ? "origin-ai"
        : originType === "external_paste"
          ? "origin-paste"
          : undefined;

    return [
      "span",
      mergeAttributes(
        { "data-origin": "" },
        HTMLAttributes,
        cssClass ? { class: cssClass } : {}
      ),
      0,
    ];
  },

  parseHTML() {
    return [{ tag: "span[data-origin]" }];
  },
});

import { Extension } from "@tiptap/core";
import { Plugin, PluginKey } from "@tiptap/pm/state";
import { DOMParser as ProseMirrorDOMParser } from "@tiptap/pm/model";
import type { Slice, MarkType, Schema } from "@tiptap/pm/model";
import type { EditorView } from "@tiptap/pm/view";

export interface PasteHandlerOptions {
  documentId: string;
  onExternalPaste?: (
    content: string,
    characterCount: number,
    sourceId: string
  ) => void;
  recentAIResponses?: string[];
  maxRecentAIResponses?: number;
}

export function classifyPaste(
  clipboardText: string,
  recentAIResponses: string[]
): "external" | "ai_internal" {
  return recentAIResponses.some((r) => r === clipboardText)
    ? "ai_internal"
    : "external";
}

function createSourceId(): string {
  if (globalThis.crypto?.randomUUID) {
    return globalThis.crypto.randomUUID();
  }

  // RFC4122-ish fallback for older runtimes.
  return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, (char) => {
    const rand = Math.floor(Math.random() * 16);
    const value = char === "x" ? rand : (rand & 0x3) | 0x8;
    return value.toString(16);
  });
}

function getClipboardText(event: ClipboardEvent, fallbackSlice: Slice) {
  return (
    event.clipboardData?.getData("text/plain") ??
    fallbackSlice.content.textBetween(0, fallbackSlice.content.size, "\n\n")
  );
}

function buildOriginMark(
  originMarkType: MarkType,
  classification: "external" | "ai_internal",
  clipboardText: string,
  sourceId: string
) {
  return originMarkType.create({
    type: classification === "ai_internal" ? "ai" : "external_paste",
    sourceId,
    originalLength: clipboardText.length,
  });
}

function parseClipboardSlice(
  event: ClipboardEvent,
  schema: Schema,
  fallbackSlice: Slice
) {
  const clipboardHtml = event.clipboardData?.getData("text/html");
  if (!clipboardHtml) {
    return fallbackSlice;
  }

  const wrapper = document.createElement("div");
  wrapper.innerHTML = clipboardHtml;
  return ProseMirrorDOMParser.fromSchema(schema).parseSlice(wrapper);
}

function applyMarkedPaste(params: {
  view: EditorView;
  from: number;
  to: number;
  parsedSlice: Slice;
  clipboardText: string;
  originMark: ReturnType<MarkType["create"]>;
}) {
  const { view, from, to, parsedSlice, clipboardText, originMark } = params;
  const { schema } = view.state;

  if (parsedSlice.content.childCount > 0) {
    const tr = view.state.tr.replaceRange(from, to, parsedSlice);
    const insertEnd = tr.mapping.map(to);
    tr.addMark(from, insertEnd, originMark);
    view.dispatch(tr);
    return;
  }

  const textNode = schema.text(clipboardText, [originMark]);
  const tr = view.state.tr.replaceWith(from, to, textNode);
  view.dispatch(tr);
}

declare module "@tiptap/core" {
  interface Storage {
    pasteHandler: {
      recentAIResponses: string[];
    };
  }

  interface Commands<ReturnType> {
    pasteHandler: {
      addRecentAIResponse: (text: string) => ReturnType;
      clearRecentAIResponses: () => ReturnType;
    };
  }
}

export const PasteHandler = Extension.create<PasteHandlerOptions>({
  name: "pasteHandler",

  addOptions() {
    return {
      documentId: "",
      onExternalPaste: undefined,
      recentAIResponses: [],
      maxRecentAIResponses: 10,
    };
  },

  addStorage() {
    return {
      recentAIResponses: [] as string[],
    };
  },

  onCreate() {
    const initial = this.options.recentAIResponses ?? [];
    const max = this.options.maxRecentAIResponses ?? 10;

    if (initial.length > 0) {
      this.storage.recentAIResponses = [...initial].slice(0, max);
    }
  },

  addCommands() {
    return {
      addRecentAIResponse:
        (text: string) =>
        () => {
          const trimmed = text.trim();
          if (!trimmed) return false;

          const max = this.options.maxRecentAIResponses ?? 10;
          const next = [
            trimmed,
            ...this.storage.recentAIResponses.filter((r: string) => r !== trimmed),
          ];
          this.storage.recentAIResponses = next.slice(0, max);
          return true;
        },

      clearRecentAIResponses:
        () =>
        () => {
          this.storage.recentAIResponses = [];
          return true;
        },
    };
  },

  addProseMirrorPlugins() {
    const { onExternalPaste } = this.options;
    const storage = this.storage;

    return [
      new Plugin({
        key: new PluginKey("pasteHandler"),
        props: {
          handlePaste(view, event, slice) {
            const clipboardText = getClipboardText(event, slice);
            if (!clipboardText) return false;

            const { schema } = view.state;
            const originMarkType = schema.marks.origin;
            if (!originMarkType) return false;

            const classification = classifyPaste(
              clipboardText,
              storage.recentAIResponses
            );

            const sourceId = createSourceId();
            const originMark = buildOriginMark(
              originMarkType,
              classification,
              clipboardText,
              sourceId
            );

            const { from, to } = view.state.selection;
            const parsedSlice = parseClipboardSlice(event, schema, slice);
            applyMarkedPaste({
              view,
              from,
              to,
              parsedSlice,
              clipboardText,
              originMark,
            });

            if (classification !== "ai_internal") {
              onExternalPaste?.(clipboardText, clipboardText.length, sourceId);
            }

            return true;
          },
        },
      }),
    ];
  },
});

import { Extension } from "@tiptap/core";
import { Plugin, PluginKey } from "@tiptap/pm/state";
import { Decoration, DecorationSet } from "@tiptap/pm/view";

export const selectionHighlightKey = new PluginKey("selectionHighlight");

interface HighlightState {
  from: number;
  to: number;
  active: boolean;
}

export const SelectionHighlight = Extension.create({
  name: "selectionHighlight",

  addProseMirrorPlugins() {
    return [
      new Plugin({
        key: selectionHighlightKey,
        state: {
          init: (): HighlightState => ({ from: 0, to: 0, active: false }),
          apply: (tr, value: HighlightState): HighlightState => {
            const meta = tr.getMeta(selectionHighlightKey) as
              | HighlightState
              | undefined;
            if (meta) return meta;
            // Map positions through document changes
            if (value.active && tr.docChanged) {
              return {
                from: tr.mapping.map(value.from),
                to: tr.mapping.map(value.to),
                active: true,
              };
            }
            return value;
          },
        },
        props: {
          decorations(state) {
            const pluginState = selectionHighlightKey.getState(
              state
            ) as HighlightState;
            if (
              !pluginState?.active ||
              pluginState.from >= pluginState.to ||
              pluginState.to > state.doc.content.size
            ) {
              return DecorationSet.empty;
            }
            return DecorationSet.create(state.doc, [
              Decoration.inline(pluginState.from, pluginState.to, {
                class: "inline-ai-highlight",
              }),
            ]);
          },
        },
      }),
    ];
  },
});

"use client";

import { useRef, useCallback, useState, useEffect } from "react";
import { updateDocument } from "@/app/actions/documents";

type SaveStatus = "idle" | "saving" | "saved" | "error";

interface UseAutoSaveOptions {
  documentId: string;
  title: string;
  debounceMs?: number;
  maxRetries?: number;
}

function normalizeSerializableContent(
  content: Record<string, unknown>
): Record<string, unknown> {
  // TipTap can emit null-prototype objects in mark attrs.
  // Normalize to plain JSON objects before crossing the Server Action boundary.
  return JSON.parse(JSON.stringify(content)) as Record<string, unknown>;
}

function countWords(content: Record<string, unknown>): number {
  const extractText = (node: Record<string, unknown>): string => {
    if (node.type === "text" && typeof node.text === "string") {
      return node.text;
    }
    if (Array.isArray(node.content)) {
      return node.content.map((child) => extractText(child as Record<string, unknown>)).join(" ");
    }
    return "";
  };

  const text = extractText(content).trim();
  return text ? text.split(/\s+/).length : 0;
}

export function useAutoSave({
  documentId,
  title,
  debounceMs = 1000,
  maxRetries = 3,
}: UseAutoSaveOptions) {
  const [status, setStatus] = useState<SaveStatus>("idle");
  const [isDirty, setIsDirty] = useState(false);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const titleRef = useRef(title);
  const documentIdRef = useRef(documentId);
  const maxRetriesRef = useRef(maxRetries);
  const lastContentRef = useRef<Record<string, unknown> | null>(null);
  const prevTitleRef = useRef(title);

  useEffect(() => {
    titleRef.current = title;
  }, [title]);

  useEffect(() => {
    documentIdRef.current = documentId;
  }, [documentId]);

  useEffect(() => {
    maxRetriesRef.current = maxRetries;
  }, [maxRetries]);

  const executeSave = useCallback(
    (content: Record<string, unknown>) => {
      const attemptSave = async (retriesLeft: number) => {
        setStatus("saving");
        try {
          await updateDocument(documentIdRef.current, {
            title: titleRef.current,
            content,
            wordCount: countWords(content),
          });
          setStatus("saved");
          setIsDirty(false);
        } catch {
          if (retriesLeft > 0) {
            const delay = Math.pow(2, maxRetriesRef.current - retriesLeft) * 1000;
            setTimeout(() => {
              attemptSave(retriesLeft - 1);
            }, delay);
          } else {
            setStatus("error");
          }
        }
      };

      attemptSave(maxRetriesRef.current);
    },
    []
  );

  const save = useCallback(
    (content: Record<string, unknown>) => {
      const normalizedContent = normalizeSerializableContent(content);
      lastContentRef.current = normalizedContent;
      setIsDirty(true);
      if (timerRef.current) {
        clearTimeout(timerRef.current);
      }

      timerRef.current = setTimeout(() => {
        executeSave(normalizedContent);
      }, debounceMs);
    },
    [debounceMs, executeSave]
  );

  // Trigger a save when only the title changes
  useEffect(() => {
    if (prevTitleRef.current !== title) {
      prevTitleRef.current = title;
      if (lastContentRef.current) {
        save(lastContentRef.current);
      }
    }
  }, [title, save]);

  const retry = useCallback(() => {
    if (lastContentRef.current && status === "error") {
      save(lastContentRef.current);
    }
  }, [save, status]);

  // Flush pending save on page hide (tab switch, navigation, refresh).
  // visibilitychange fires reliably and browsers keep async requests alive briefly after it.
  useEffect(() => {
    const flushPendingSave = () => {
      if (timerRef.current && lastContentRef.current) {
        clearTimeout(timerRef.current);
        timerRef.current = null;
        executeSave(lastContentRef.current);
      }
    };

    const handleVisibilityChange = () => {
      if (document.visibilityState === "hidden") {
        flushPendingSave();
      }
    };

    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      flushPendingSave();
      if (isDirty) {
        e.preventDefault();
      }
    };

    document.addEventListener("visibilitychange", handleVisibilityChange);
    window.addEventListener("beforeunload", handleBeforeUnload);
    return () => {
      document.removeEventListener("visibilitychange", handleVisibilityChange);
      window.removeEventListener("beforeunload", handleBeforeUnload);
    };
  }, [isDirty, executeSave]);

  return { save, status, retry, isDirty };
}

"use client";

import { useEffect, useRef, useCallback } from "react";
import { createRevision } from "@/app/actions/revisions";

interface UseRevisionsOptions {
  documentId: string;
  intervalMs?: number;
  activityTimeoutMs?: number;
}

export function useRevisions({
  documentId,
  intervalMs = 30000,
  activityTimeoutMs = 60000,
}: UseRevisionsOptions) {
  const contentRef = useRef<Record<string, unknown> | null>(null);
  const lastActivity = useRef<number>(0);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const updateContent = useCallback(
    (content: Record<string, unknown>) => {
      contentRef.current = content;
      lastActivity.current = Date.now();
    },
    []
  );

  const createAIRevision = useCallback(async () => {
    if (!contentRef.current) return;

    try {
      await createRevision({
        documentId,
        content: contentRef.current,
        trigger: "ai_interaction",
      });
    } catch {
      // Best effort — don't break AI workflow
    }
  }, [documentId]);

  useEffect(() => {
    // Set up interval-based revision creation every 30 seconds
    intervalRef.current = setInterval(async () => {
      const isActive =
        Date.now() - lastActivity.current < activityTimeoutMs;

      if (contentRef.current && isActive) {
        try {
          await createRevision({
            documentId,
            content: contentRef.current,
            trigger: "interval",
          });
        } catch {
          // Revision failed — continue silently
        }
      }
    }, intervalMs);

    return () => {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
      }
    };
  }, [documentId, intervalMs, activityTimeoutMs]);

  return { updateContent, createAIRevision };
}

"use client";

import { useEffect, useRef, useCallback } from "react";
import {
  startSession,
  heartbeat,
  endSession,
} from "@/app/actions/sessions";

interface UseSessionOptions {
  documentId: string;
  heartbeatIntervalMs?: number;
  activityTimeoutMs?: number;
}

export function useSession({
  documentId,
  heartbeatIntervalMs = 30000,
  activityTimeoutMs = 60000,
}: UseSessionOptions) {
  const sessionIdRef = useRef<string | null>(null);
  const lastActivity = useRef<number>(0);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const markActive = useCallback(() => {
    lastActivity.current = Date.now();
  }, []);

  useEffect(() => {
    let mounted = true;
    lastActivity.current = Date.now();

    async function init() {
      try {
        const session = await startSession(documentId);
        if (mounted && session) {
          sessionIdRef.current = session.id;
        }
      } catch {
        // Session start failed — continue without tracking
      }
    }

    init();

    // Set up heartbeat interval
    intervalRef.current = setInterval(async () => {
      const isActive =
        Date.now() - lastActivity.current < activityTimeoutMs;

      if (sessionIdRef.current && isActive) {
        try {
          await heartbeat(sessionIdRef.current);
        } catch {
          // Heartbeat failed — continue silently
        }
      }
    }, heartbeatIntervalMs);

    return () => {
      mounted = false;

      if (intervalRef.current) {
        clearInterval(intervalRef.current);
      }

      // End session on unmount
      if (sessionIdRef.current) {
        endSession(sessionIdRef.current).catch(() => {
          // End session failed — best effort
        });
      }
    };
  }, [documentId, heartbeatIntervalMs, activityTimeoutMs]);

  return { markActive };
}

