    };
  }

  return undefined;
}

import { z } from "zod";

const MAX_MESSAGE_BYTES = 25_000;
const MAX_MESSAGE_PARTS = 200;

function isWithinMessageByteBudget(value: unknown): boolean {
  try {
    const serialized = JSON.stringify(value);
    if (!serialized) return true;
    return new TextEncoder().encode(serialized).length <= MAX_MESSAGE_BYTES;
  } catch {
    return false;
  }
}

const messagePartSchema = z
  .object({
    type: z.string().max(64),
    text: z.string().max(20_000).optional(),
  })
  .passthrough();

const chatMessageSchema = z
  .object({
    id: z.string().max(256).optional(),
    role: z.enum(["user", "assistant", "system", "tool"]),
    content: z
      .union([z.string().max(20_000), z.array(messagePartSchema).max(MAX_MESSAGE_PARTS)])
      .optional(),
    parts: z.array(messagePartSchema).max(MAX_MESSAGE_PARTS).optional(),
  })
  .passthrough()
  .superRefine((value, ctx) => {
    if (!isWithinMessageByteBudget(value)) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Message payload too large",
      });
    }
  });

const completionMessageSchema = z
  .object({
    role: z.enum(["user", "assistant", "system", "tool"]),
    content: z
      .union([z.string().max(20_000), z.array(messagePartSchema).max(MAX_MESSAGE_PARTS)])
      .optional(),
    parts: z.array(messagePartSchema).max(MAX_MESSAGE_PARTS).optional(),
  })
  .passthrough()
  .superRefine((value, ctx) => {
    if (!isWithinMessageByteBudget(value)) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Message payload too large",
      });
    }
  });

export const chatRequestSchema = z.object({
  provider: z.enum(["anthropic", "openai"]).optional(),
  model: z.string().max(100).optional(),
  messages: z.array(chatMessageSchema).min(1).max(100),
  documentContext: z.string().max(50_000).optional(),
  threadId: z.string().uuid().optional(),
});

export const aiCompletionSchema = z
  .object({
    mode: z.enum(["inline", "side_panel", "freeform"]),
    provider: z.enum(["anthropic", "openai"]).optional(),
    model: z.string().max(100).optional(),
    prompt: z.string().max(10_000).optional(),
    selectedText: z.string().max(10_000).optional(),
    context: z.string().max(100_000).optional(),
    messages: z.array(completionMessageSchema).max(50).optional(),
  })
  .refine((data) => data.prompt || (data.messages && data.messages.length > 0), {
    message: "Either prompt or messages must be provided",
  });

export function getSystemPrompt(
  mode: "inline" | "side_panel" | "freeform" | "chat"
): string {
  switch (mode) {
    case "inline":
      return "You are a writing assistant helping to improve selected text. Provide direct text replacements without explanations or markdown formatting. Match the style and tone of the surrounding content.";
    case "side_panel":
      return "You are a writing assistant with full access to the document context. Help the user with research, brainstorming, and writing suggestions. Be conversational and helpful.";
    case "freeform":
      return "You are a writing assistant. Help the user with their writing request. Provide clear, actionable content that can be inserted into a document.";
    case "chat":
      return "You are a writing assistant embedded in a document editor. You have access to the writer's full document. Help with research, critique, brainstorming, and structural analysis. When critiquing, point to specific parts of the text. Be conversational and direct. Do not rewrite the document — offer observations and suggestions the writer can act on themselves.";
  }
}

import { auth } from "@/auth";
import { db } from "@/lib/db";
import { aiInteractions, documents, pasteEvents } from "@/lib/db/schema";
import { and, eq, isNull } from "drizzle-orm";
import { NextResponse } from "next/server";

const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

export const PRIVATE_HEADERS = {
  "Cache-Control": "private, no-store, max-age=0",
} as const;

type JsonResponse = ReturnType<typeof NextResponse.json>;

type OwnedDocument = typeof documents.$inferSelect;
type Interaction = typeof aiInteractions.$inferSelect;
type PasteEvent = typeof pasteEvents.$inferSelect;

function privateJson(payload: unknown, status: number): JsonResponse {
  return NextResponse.json(payload, { status, headers: PRIVATE_HEADERS });
}

export type OwnedDocumentResult =
  | {
      document: OwnedDocument;
      userId: string;
    }
  | {
      response: JsonResponse;
    };

export async function resolveOwnedDocumentRequest(
  documentId: string
): Promise<OwnedDocumentResult> {
  if (!UUID_RE.test(documentId)) {
    return { response: privateJson({ error: "Not found" }, 404) };
  }

  const session = await auth();
  const userId = session?.user?.id;
  if (!userId) {
    return { response: privateJson({ error: "Unauthorized" }, 401) };
  }

  const [document] = await db
    .select()
    .from(documents)
    .where(and(eq(documents.id, documentId), isNull(documents.deletedAt)));

  if (!document || document.userId !== userId) {
    return { response: privateJson({ error: "Not found" }, 404) };
  }

  return { document, userId };
}

export function toAuditInteraction(interaction: Interaction) {
  return {
    sourceId: interaction.id,
    mode: interaction.mode,
    prompt: interaction.prompt,
    response: interaction.response,
    action: interaction.action,
    createdAt: interaction.createdAt,
  };
}

export function toAuditPasteEvent(pasteEvent: PasteEvent) {
  return {
    sourceId: pasteEvent.id,
    sourceType: pasteEvent.sourceType,
    characterCount: pasteEvent.characterCount,
    createdAt: pasteEvent.createdAt,
  };
}

export class ReadJsonBodyError extends Error {
  readonly status: number;

  constructor(status: number, message: string) {
    super(message);
    this.status = status;
  }
}

export async function readJsonBody(
  req: Request,
  maxBytes: number
): Promise<unknown> {
  const contentLength = req.headers.get("content-length");
  if (contentLength) {
    const size = Number(contentLength);
    if (Number.isFinite(size) && size > maxBytes) {
      throw new ReadJsonBodyError(413, "Request body too large");
    }
  }

  const bodyText = await req.text();
  const bodyBytes = new TextEncoder().encode(bodyText).length;
  if (bodyBytes > maxBytes) {
    throw new ReadJsonBodyError(413, "Request body too large");
  }

  if (!bodyText.trim()) {
    throw new ReadJsonBodyError(400, "Request body is required");
  }

  try {
    return JSON.parse(bodyText);
  } catch {
    throw new ReadJsonBodyError(400, "Invalid JSON body");
  }
}

import { auth } from "@/auth";
import { db } from "@/lib/db";
import { documents, users } from "@/lib/db/schema";
import { eq, and, isNull } from "drizzle-orm";

const USER_IDENTITY_SELECT = {
  id: users.id,
  email: users.email,
  name: users.name,
  image: users.image,
};

async function findUserById(userId: string) {
  const [user] = await db
    .select(USER_IDENTITY_SELECT)
    .from(users)
    .where(eq(users.id, userId));

  return user;
}

async function findUserByEmail(email: string) {
  const [user] = await db
    .select(USER_IDENTITY_SELECT)
    .from(users)
    .where(eq(users.email, email));

  return user;
}

function mergeSessionUser(
  sessionUser: NonNullable<Awaited<ReturnType<typeof auth>>["user"]>,
  existingUser: Awaited<ReturnType<typeof findUserById>>
) {
  return {
    ...sessionUser,
    id: existingUser.id,
    email: existingUser.email ?? sessionUser.email ?? null,
    name: existingUser.name ?? sessionUser.name ?? null,
    image: existingUser.image ?? sessionUser.image ?? null,
  };
}

export async function requireAuth() {
  const session = await auth();
  const sessionUser = session?.user;

  if (!sessionUser?.id) {
    throw new Error("Unauthorized");
  }

  const existingById = await findUserById(sessionUser.id);
  if (existingById) {
    return mergeSessionUser(sessionUser, existingById);
  }

  if (!sessionUser.email) {
    throw new Error("Unauthorized");
  }

  const existingByEmail = await findUserByEmail(sessionUser.email);
  if (existingByEmail) {
    return mergeSessionUser(sessionUser, existingByEmail);
  }

  throw new Error("Unauthorized");
}

export async function requireDocumentOwner(documentId: string) {
  const user = await requireAuth();

  const [document] = await db
    .select()
    .from(documents)
    .where(
      and(eq(documents.id, documentId), isNull(documents.deletedAt))
    );

  if (!document) {
    throw new Error("Not found");
  }

  if (document.userId !== user.id) {
    throw new Error("Forbidden");
  }

  return { user, document };
}

export const DEFAULT_E2E_CALLBACK_URL = "/dashboard";
const DEFAULT_E2E_USERS = ["author-a", "author-b"];
const E2E_EMAIL_DOMAIN = "provenance.local";

type EnvSource = Record<string, string | undefined>;

export interface E2ELoginRequest {
  token: string;
  userKey: string;
  callbackUrl: string;
}

export interface E2EUserProfile {
  userKey: string;
  email: string;
  name: string;
}

function readEnv(env?: EnvSource): EnvSource {
  return env ?? (process.env as EnvSource);
}

function toSingleValue(value: string | string[] | undefined): string | undefined {
  return Array.isArray(value) ? value[0] : value;
}

function titleCaseUserKey(userKey: string): string {
  return userKey
    .split("-")
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

export function isE2EAuthEnabled(env?: EnvSource): boolean {
  const source = readEnv(env);
  return (
    source.E2E_AUTH_ENABLED === "true" &&
    typeof source.E2E_AUTH_SECRET === "string" &&
    source.E2E_AUTH_SECRET.length > 0
  );
}

export function getAllowedE2EUsers(env?: EnvSource): string[] {
  const source = readEnv(env);
  const configuredUsers = source.E2E_AUTH_USERS
    ?.split(",")
    .map((value) => value.trim())
    .filter(Boolean);

  return configuredUsers && configuredUsers.length > 0
    ? configuredUsers
    : DEFAULT_E2E_USERS;
}

export function sanitizeE2ECallbackUrl(callbackUrl?: string): string | null {
  if (!callbackUrl) return DEFAULT_E2E_CALLBACK_URL;
  if (!callbackUrl.startsWith("/")) return null;
  if (callbackUrl.startsWith("//")) return null;
  if (callbackUrl.includes("://")) return null;
  return callbackUrl;
}

export function resolveE2EUserProfile(
  userKey: string,
  env?: EnvSource
): E2EUserProfile | null {
  if (!getAllowedE2EUsers(env).includes(userKey)) {
    return null;
  }

  return {
    userKey,
    email: `e2e+${userKey}@${E2E_EMAIL_DOMAIN}`,
    name: `E2E ${titleCaseUserKey(userKey)}`,
  };
}

export function parseE2ELoginSearchParams(
  searchParams: Record<string, string | string[] | undefined>,
  env?: EnvSource
): E2ELoginRequest | null {
  const source = readEnv(env);
  if (!isE2EAuthEnabled(source)) return null;

  const token = toSingleValue(searchParams.token);
  const userKey = toSingleValue(searchParams.user);
  const callbackUrl = sanitizeE2ECallbackUrl(
    toSingleValue(searchParams.callbackUrl)
  );

  if (!token || token !== source.E2E_AUTH_SECRET) return null;
  if (!userKey || !resolveE2EUserProfile(userKey, source)) return null;
  if (!callbackUrl) return null;

  return {
    token,
    userKey,
    callbackUrl,
  };
}

export async function upsertE2EUser(
  userKey: string,
  env?: EnvSource
): Promise<{ id: string; email: string | null; name: string | null } | null> {
  const [{ db }, { users }] = await Promise.all([
    import("@/lib/db"),
    import("@/lib/db/schema"),
  ]);
  const profile = resolveE2EUserProfile(userKey, env);
  if (!profile) return null;

  const [user] = await db
    .insert(users)
    .values({
      email: profile.email,
      name: profile.name,
      emailVerified: new Date(),
    })
    .onConflictDoUpdate({
      target: users.email,
      set: {
        name: profile.name,
        emailVerified: new Date(),
      },
    })
    .returning({
      id: users.id,
      email: users.email,
      name: users.name,
    });

  return user ?? null;
}

export async function authorizeE2ECredentials(
  credentials: Partial<Record<string, unknown>> | undefined,
  env?: EnvSource
): Promise<{ id: string; email: string | null; name: string | null } | null> {
  const source = readEnv(env);
  if (!isE2EAuthEnabled(source)) return null;

  const token =
    typeof credentials?.token === "string" ? credentials.token : undefined;
  const userKey =
    typeof credentials?.userKey === "string" ? credentials.userKey : undefined;

  if (!token || token !== source.E2E_AUTH_SECRET) return null;
  if (!userKey || !resolveE2EUserProfile(userKey, source)) return null;

  return upsertE2EUser(userKey, source);
}

