interface TipTapMark {
  type: string;
  attrs?: Record<string, unknown>;
}

interface TipTapNode {
  type?: string;
  text?: string;
  content?: TipTapNode[];
  marks?: TipTapMark[];
}

interface BadgeStats {
  ai_percentage: number;
  external_paste_percentage: number;
  total_characters: number;
}

interface AiInteractionLike {
  action?: string | null;
  response?: string | null;
}

type OriginType = "human" | "ai" | "external_paste" | "unknown";

/** Count characters as Unicode code points, not UTF-16 code units. */
function countChars(text: string): number {
  return Array.from(text).length;
}

function walkTextNodes(
  node: TipTapNode,
  callback: (text: string, marks?: TipTapMark[]) => void
) {
  if (node.text != null) {
    callback(node.text, node.marks);
    return;
  }

  if (node.content) {
    for (const child of node.content) {
      walkTextNodes(child, callback);
    }
  }
}

/**
 * Compute Levenshtein edit distance between two strings.
 * Operates on Unicode code points (not UTF-16 code units) for correct
 * handling of emoji and other characters outside the Basic Multilingual Plane.
 */
export function editDistance(a: string, b: string): number {
  // Spread to get code points instead of UTF-16 code units
  const aChars = [...a];
  const bChars = [...b];
  const m = aChars.length;
  const n = bChars.length;
  if (m === 0) return n;
  if (n === 0) return m;
  if (a === b) return 0;

  // Two-row DP (O(n) space)
  let prev = Array.from({ length: n + 1 }, (_, i) => i);
  let curr = new Array<number>(n + 1);

  for (let i = 1; i <= m; i++) {
    curr[0] = i;
    for (let j = 1; j <= n; j++) {
      const cost = aChars[i - 1] === bChars[j - 1] ? 0 : 1;
      curr[j] = Math.min(prev[j] + 1, curr[j - 1] + 1, prev[j - 1] + cost);
    }
    [prev, curr] = [curr, prev];
  }

  return prev[n];
}

const MIN_RESPONSE_MATCH_CHARS = 20;

function findNonOverlappingMatch(
  text: string,
  pattern: string,
  occupied: boolean[]
): number {
  let fromIndex = 0;
  const maxStart = text.length - pattern.length;
  while (fromIndex <= maxStart) {
    const idx = text.indexOf(pattern, fromIndex);
    if (idx === -1) return -1;

    let overlaps = false;
    for (let i = idx; i < idx + pattern.length; i++) {
      if (occupied[i]) {
        overlaps = true;
        break;
      }
    }

    if (!overlaps) return idx;
    fromIndex = idx + 1;
  }

  return -1;
}

/**
 * Fallback estimator for legacy snapshots that have missing/stripped origin attrs.
 * Counts accepted AI responses that are still present verbatim in final text.
 */
export function estimateRetainedAiCharactersFromAcceptedResponses(
  documentText: string,
  interactions: AiInteractionLike[]
): number {
  if (!documentText || interactions.length === 0) return 0;

  const acceptedResponses = interactions
    .filter(
      (interaction) =>
        interaction.action === "accepted" &&
        typeof interaction.response === "string"
    )
    .map((interaction) => interaction.response?.trim() ?? "")
    .filter((response) => countChars(response) >= MIN_RESPONSE_MATCH_CHARS)
    .sort((a, b) => countChars(b) - countChars(a));

  if (acceptedResponses.length === 0) return 0;

  const occupied = new Array(documentText.length).fill(false);
  let retainedChars = 0;

  for (const response of acceptedResponses) {
    const matchStart = findNonOverlappingMatch(documentText, response, occupied);
    if (matchStart === -1) continue;

    for (let i = matchStart; i < matchStart + response.length; i++) {
      occupied[i] = true;
    }
    retainedChars += countChars(response);
  }

  return retainedChars;
}

function getOriginType(mark?: TipTapMark): OriginType {
  const rawType = mark?.attrs?.type;
  if (rawType === "human" || rawType === "ai" || rawType === "external_paste") {
    return rawType;
  }
  return "unknown";
}

function isAIMarkSubstantiallyModified(text: string, originMark: TipTapMark): boolean {
  const originalLength = originMark.attrs?.originalLength as number | null;
  const originalText = originMark.attrs?.originalText as string | null;
  const currentLength = countChars(text);

  if (originalText != null) {
    const distance = editDistance(originalText, text);
    const maxLen = Math.max(countChars(originalText), currentLength);
    return maxLen > 0 && distance / maxLen > 0.2;
  }

  if (!originalLength || originalLength <= 0) {
    return false;
  }

  return (
    Math.abs(currentLength - originalLength) /
      Math.max(originalLength, currentLength) >
    0.2
  );
}

export function calculateMetrics(doc: TipTapNode): BadgeStats {
  let aiChars = 0;
  let humanChars = 0;
  let externalPasteChars = 0;

  walkTextNodes(doc, (text, marks) => {
    const originMark = marks?.find((m) => m.type === "origin");
    const length = countChars(text);
    const originType = getOriginType(originMark);

    if (originType === "ai") {
      if (originMark && isAIMarkSubstantiallyModified(text, originMark)) {
        humanChars += length;
      } else {
        aiChars += length;
      }
      return;
    }

    if (originType === "external_paste") {
      externalPasteChars += length;
      return;
    }

    humanChars += length;
  });

  const total = aiChars + humanChars + externalPasteChars;
  // Use Math.floor to prevent ai% + external% from exceeding 100%
  const aiPct = total > 0 ? Math.floor((aiChars / total) * 100) : 0;
  const externalPct = total > 0 ? Math.floor((externalPasteChars / total) * 100) : 0;
  return {
    ai_percentage: aiPct,
    external_paste_percentage: externalPct,
    total_characters: total,
  };
}

interface RawEvent {
  type: "ai_interaction" | "paste" | "session_start" | "session_end" | "revision";
  timestamp: string | Date | null;
  data: Record<string, unknown>;
}

export interface DayGroup {
  date: string; // YYYY-MM-DD
  label: string; // "Jan 15, 2025"
  sessions: SessionGroup[];
}

export interface SessionGroup {
  startTime: string | null;
  endTime: string | null;
  events: TimelineEvent[];
}

export interface TimelineEvent {
  type: "ai_interaction" | "paste" | "revision";
  timestamp: string | Date | null;
  data: Record<string, unknown>;
}

export interface RevisionCluster {
  count: number;
  startTime: string | Date | null;
  endTime: string | Date | null;
  durationMinutes: number;
}

function toDateKey(ts: string | Date | null): string {
  if (!ts) return "unknown";
  const d = new Date(ts);
  return d.toISOString().split("T")[0];
}

function formatDateLabel(dateKey: string): string {
  if (dateKey === "unknown") return "Unknown Date";
  const d = new Date(dateKey + "T00:00:00");
  return d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
}

function sortByTimestamp(events: RawEvent[]): RawEvent[] {
  return [...events].sort((a, b) => {
    const ta = a.timestamp ? new Date(a.timestamp).getTime() : 0;
    const tb = b.timestamp ? new Date(b.timestamp).getTime() : 0;
    return ta - tb;
  });
}

function toTimelineEvent(event: RawEvent): TimelineEvent {
  return {
    type: event.type as TimelineEvent["type"],
    timestamp: event.timestamp,
    data: event.data,
  };
}

function createSession(timestamp: string | Date | null): SessionGroup {
  return {
    startTime: timestamp?.toString() ?? null,
    endTime: null,
    events: [],
  };
}

function singleSessionWithoutBoundaries(events: RawEvent[]): SessionGroup[] {
  const nonSessionEvents = events.filter(
    (event) => event.type !== "session_start" && event.type !== "session_end"
  );

  return [
    {
      startTime: nonSessionEvents[0]?.timestamp?.toString() ?? null,
      endTime:
        nonSessionEvents[nonSessionEvents.length - 1]?.timestamp?.toString() ??
        null,
      events: nonSessionEvents.map(toTimelineEvent),
    },
  ];
}

function isSessionMarker(event: RawEvent) {
  return event.type === "session_start" || event.type === "session_end";
}

function handleSessionMarker(params: {
  event: RawEvent;
  currentSession: SessionGroup | null;
  sessions: SessionGroup[];
}) {
  const { event, sessions } = params;
  let { currentSession } = params;

  if (event.type === "session_start") {
    if (currentSession) {
      sessions.push(currentSession);
    }
    return createSession(event.timestamp);
  }

  if (currentSession) {
    currentSession.endTime = event.timestamp?.toString() ?? null;
    sessions.push(currentSession);
  }

  return null;
}

export function groupEventsByDay(events: RawEvent[]): DayGroup[] {
  const dayMap = new Map<string, RawEvent[]>();

  for (const event of events) {
    const key = toDateKey(event.timestamp);
    if (!dayMap.has(key)) dayMap.set(key, []);
    dayMap.get(key)!.push(event);
  }

  const days: DayGroup[] = [];
  const sortedKeys = [...dayMap.keys()].sort();

  for (const key of sortedKeys) {
    const dayEvents = dayMap.get(key)!;
    days.push({
      date: key,
      label: formatDateLabel(key),
      sessions: groupIntoSessions(dayEvents),
    });
  }

  return days;
}

function groupIntoSessions(events: RawEvent[]): SessionGroup[] {
  const hasSessionMarkers = events.some((event) => event.type === "session_start");
  if (!hasSessionMarkers) {
    return singleSessionWithoutBoundaries(events);
  }

  const sessions: SessionGroup[] = [];
  const sorted = sortByTimestamp(events);
  let currentSession: SessionGroup | null = null;

  for (const event of sorted) {
    if (isSessionMarker(event)) {
      currentSession = handleSessionMarker({
        event,
        currentSession,
        sessions,
      });
      continue;
    }

    if (!currentSession) {
      currentSession = createSession(event.timestamp);
    }
    currentSession.events.push(toTimelineEvent(event));
  }

  if (currentSession) sessions.push(currentSession);

  return sessions;
}

export function clusterRevisions(events: TimelineEvent[]): (TimelineEvent | RevisionCluster)[] {
  const result: (TimelineEvent | RevisionCluster)[] = [];
  let revisionBuffer: TimelineEvent[] = [];

  const flushRevisions = () => {
    if (revisionBuffer.length === 0) return;
    if (revisionBuffer.length <= 2) {
      result.push(...revisionBuffer);
    } else {
      const first = revisionBuffer[0].timestamp;
      const last = revisionBuffer[revisionBuffer.length - 1].timestamp;
      const startMs = first ? new Date(first).getTime() : 0;
      const endMs = last ? new Date(last).getTime() : 0;
      result.push({
        count: revisionBuffer.length,
        startTime: first,
        endTime: last,
        durationMinutes: Math.round((endMs - startMs) / 60000),
      });
    }
    revisionBuffer = [];
  };

  for (const event of events) {
    if (event.type === "revision") {
      revisionBuffer.push(event);
    } else {
      flushRevisions();
      result.push(event);
    }
  }
  flushRevisions();

  return result;
}

export function getEventCounts(events: RawEvent[]): Record<string, number> {
  const counts: Record<string, number> = {
    ai_interaction: 0,
    paste: 0,
    revision: 0,
  };

  for (const event of events) {
    if (event.type in counts) {
      counts[event.type]++;
    }
  }

  return counts;
}

interface TipTapNode {
  type?: string;
  text?: string;
  content?: TipTapNode[];
  marks?: { type: string; attrs?: Record<string, unknown> }[];
}

export function extractPlainText(doc: TipTapNode): string {
  const parts: string[] = [];

  function walk(node: TipTapNode) {
    if (node.text) {
      parts.push(node.text);
      return;
    }

    if (node.content) {
      for (const child of node.content) {
        walk(child);
      }

      // Add newline after block-level nodes (paragraph, heading, etc.)
      if (
        node.type &&
        node.type !== "doc" &&
        node.type !== "text" &&
        parts.length > 0
      ) {
        parts.push("\n");
      }
    }
  }

  walk(doc);

  return parts.join("").trim();
}

import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

import NextAuth from "next-auth";
import authConfig from "./auth.config";

const { auth } = NextAuth(authConfig);

export default auth((req) => {
  const isLoggedIn = !!req.auth;
  const { pathname } = req.nextUrl;

  const isProtectedRoute =
    pathname.startsWith("/dashboard") || pathname.startsWith("/editor");

  if (isProtectedRoute && !isLoggedIn) {
    const loginUrl = new URL("/login", req.nextUrl.origin);
    loginUrl.searchParams.set("callbackUrl", pathname);
    return Response.redirect(loginUrl);
  }
});

export const config = {
  matcher: ["/dashboard/:path*", "/editor/:path*"],
};

